INSERT INTO position (id, owner_id, name, type, description, youtube_url, visibility, created_at, updated_at, version) OVERRIDING SYSTEM VALUE VALUES
(1,  1, 'Standing Neutral',          'STANDING',       'Ambos luchadores de pie, sin clinch. Posición de inicio de combate.',                                                                                    'https://www.youtube.com/watch?v=j5uF1s3g-sM', 'PUBLIC', NOW(), NOW(), 0),
(2,  1, 'Clinch',                    'STANDING',       'Cuerpo a cuerpo de pie. Base para derribos, proyecciones y guillotinas de pie.',                                                                         'https://www.youtube.com/watch?v=CKrKMjZgGU4', 'PUBLIC', NOW(), NOW(), 0),
(3,  1, 'Single Leg',                'STANDING',       'Control de una pierna del oponente de pie. Transición al derribo single leg.',                                                                           'https://www.youtube.com/watch?v=mRIDD2zoKJ8', 'PUBLIC', NOW(), NOW(), 0),
(4,  1, 'Double Leg',                'STANDING',       'Control de ambas piernas del oponente de pie. Transición al derribo double leg.',                                                                        'https://www.youtube.com/watch?v=tgIXxV6Ax1o', 'PUBLIC', NOW(), NOW(), 0),
(5,  1, 'Arm Drag Position',         'STANDING',       'Arrastre de brazo de pie para llegar a la espalda o ejecutar derribo.',                                                                                  'https://www.youtube.com/watch?v=e_c7G5T_ZR8', 'PUBLIC', NOW(), NOW(), 0),
(6,  1, 'Full Mount',                'TOP',            'Montado encima del oponente en decúbito supino. Posición dominante alta. Base para armbar, triángulo y estrangulaciones.',                               'https://www.youtube.com/watch?v=yOWgx8rVnzU', 'PUBLIC', NOW(), NOW(), 0),
(7,  1, 'High Mount',                'TOP',            'Mount con las rodillas cerca de las axilas del oponente. Mayor control y acceso a ataques de cuello.',                                                   'https://www.youtube.com/watch?v=_uuWD4CxRDk', 'PUBLIC', NOW(), NOW(), 0),
(8,  1, 'Back Mount',                'TOP',            'Control de espalda con ganchos (hooks) insertados. La posición más dominante del BJJ. Acceso directo a RNC y bow-and-arrow.',                           'https://www.youtube.com/watch?v=CRllVj7jriY', 'PUBLIC', NOW(), NOW(), 0),
(9,  1, 'Side Control',              'TOP',            'Control lateral sobre el oponente, perpendicular al cuerpo. Posición muy dominante. Base para kimura, americana y papercutter.',                         'https://www.youtube.com/watch?v=VF8GrJdysv0', 'PUBLIC', NOW(), NOW(), 0),
(10, 1, 'North South',               'TOP',            'Control perpendicular sobre la cabeza del oponente, mirando hacia sus pies. Ataque north-south choke y kimura.',                                         'https://www.youtube.com/watch?v=0hEKXaDY0gQ', 'PUBLIC', NOW(), NOW(), 0),
(11, 1, 'Knee On Belly',             'TOP',            'Rodilla sobre el abdomen del oponente. Posición transitoria con opciones de estrangulación y armbar.',                                                   'https://www.youtube.com/watch?v=BHUYEm0ve9A', 'PUBLIC', NOW(), NOW(), 0),
(12, 1, 'Scarf Hold',                'TOP',            'Control de cabeza y brazo desde el suelo (kesa gatame). Ataque a estrangulación y americana.',                                                           'https://www.youtube.com/watch?v=3w6xQmLwcHM', 'PUBLIC', NOW(), NOW(), 0),
(13, 1, 'Turtle Top',                'TOP',            'Encima del oponente en posición de tortuga. Ataque clock choke, anaconda y toma de espalda.',                                                            'https://www.youtube.com/watch?v=8flgjYr6YLo', 'PUBLIC', NOW(), NOW(), 0),
(14, 1, 'Crucifix',                  'TOP',            'Un brazo del oponente atrapado entre las piernas, el otro controlado. Ataque RNC o estrangulaciones.',                                                   'https://www.youtube.com/watch?v=rCQsaENYkTE', 'PUBLIC', NOW(), NOW(), 0),
(15, 1, 'Leg Entanglement',          'GROUND_NEUTRAL', 'Ashi garami básico para leg locks. Single ashi garami. Posición de enredo de piernas.',                                                                  'https://www.youtube.com/watch?v=cHjSimUDoP4', 'PUBLIC', NOW(), NOW(), 0),
(16, 1, '50/50',                     'GROUND_NEUTRAL', 'Enredo de piernas simétrico. Ambos luchadores atacan heel hooks simultáneamente. Alta relevancia en no-gi moderno.',                                     'https://www.youtube.com/watch?v=mKbMqB6I9FI', 'PUBLIC', NOW(), NOW(), 0),
(17, 1, 'Outside Heel Hook Position','GROUND_NEUTRAL', 'Ashi garami exterior. Posición para outside heel hook atacando la rodilla externa.',                                                                      'https://www.youtube.com/watch?v=zQ-FNH5a01k', 'PUBLIC', NOW(), NOW(), 0),
(18, 1, 'Seated Guard',              'GROUND_NEUTRAL', 'Guardia sentada (combat base). Posición neutral de inicio en el suelo.',                                                                                 'https://www.youtube.com/watch?v=g5HArwX8Ty0', 'PUBLIC', NOW(), NOW(), 0),
(19, 1, 'Closed Guard',              'BOTTOM',         'Guardia cerrada: piernas cruzadas en la espalda del oponente. La guardia fundamental del BJJ.',                                                          'https://www.youtube.com/watch?v=otskR_OjuBU', 'PUBLIC', NOW(), NOW(), 0),
(20, 1, 'Half Guard',                'BOTTOM',         'Media guardia: una pierna del oponente atrapada entre las propias. Posición de abajo muy versátil.',                                                     'https://www.youtube.com/watch?v=Xzvab-kp9qA', 'PUBLIC', NOW(), NOW(), 0),
(21, 1, 'Z-Guard',                   'BOTTOM',         'Media guardia con la espinilla interpuesta como escudo (knee shield). Mayor control de distancia.',                                                       'https://www.youtube.com/watch?v=NsRHHZk5Nx4', 'PUBLIC', NOW(), NOW(), 0),
(22, 1, 'Deep Half Guard',           'BOTTOM',         'Media guardia profunda: debajo del oponente controlando su pierna lejana. Acceso a barridos y toma de espalda.',                                         'https://www.youtube.com/watch?v=zDD2ORNn_yw', 'PUBLIC', NOW(), NOW(), 0),
(23, 1, 'Lockdown',                  'BOTTOM',         'Media guardia con enganche de pierna en figura de 4. Sistema 10th Planet. Limita el paso del oponente.',                                                 'https://www.youtube.com/watch?v=tcS7oBdpRW0', 'PUBLIC', NOW(), NOW(), 0),
(24, 1, 'Butterfly Guard',           'BOTTOM',         'Guardia mariposa: ganchos de pie bajo los muslos del oponente sentado. Barridos explosivos y toma de espalda.',                                         'https://www.youtube.com/watch?v=HCpJsH0K7l0', 'PUBLIC', NOW(), NOW(), 0),
(25, 1, 'De La Riva Guard',          'BOTTOM',         'DLR: gancho externo en la pierna delantera del oponente. Barridos, berimbolo y transiciones a leg locks.',                                               'https://www.youtube.com/watch?v=-LhSBH3BBFE', 'PUBLIC', NOW(), NOW(), 0),
(26, 1, 'Reverse De La Riva',        'BOTTOM',         'RDLR: gancho interno en la pierna delantera. Acceso directo a single leg X y leg entanglements.',                                                        'https://www.youtube.com/watch?v=lj985a5UJl0', 'PUBLIC', NOW(), NOW(), 0),
(27, 1, 'Spider Guard',              'BOTTOM',         'Pies en bíceps del oponente con control de mangas. Solo gi. Triángulos, omoplatas y barridos.',                                                          'https://www.youtube.com/watch?v=oxeZThdCoW8', 'PUBLIC', NOW(), NOW(), 0),
(28, 1, 'Lasso Guard',               'BOTTOM',         'Pierna enroscada en el brazo del oponente (gi). Control extremo del brazo. Barridos y ataques articulares.',                                             'https://www.youtube.com/watch?v=9r6mDJMpfYs', 'PUBLIC', NOW(), NOW(), 0),
(29, 1, 'X-Guard',                   'BOTTOM',         'Configuración en X con ambas piernas controlando caderas del oponente. Barridos de elevación y technical stands.',                                       'https://www.youtube.com/watch?v=I_plwm61noM', 'PUBLIC', NOW(), NOW(), 0),
(30, 1, 'Single Leg X',              'BOTTOM',         'SLX / Ashi garami: una pierna del oponente inmovilizada. El punto de entrada estándar para el juego de leg locks moderno.',                             'https://www.youtube.com/watch?v=OaHVPQVHrMs', 'PUBLIC', NOW(), NOW(), 0),
(31, 1, 'K-Guard',                   'BOTTOM',         'Guardia dinámica que combina gancho exterior con control del tobillo. Acceso a heel hooks y barridos.',                                                  'https://www.youtube.com/watch?v=2b7bqY7iZBs', 'PUBLIC', NOW(), NOW(), 0),
(32, 1, 'Rubber Guard',              'BOTTOM',         'Sistema 10th Planet: pierna sobre el cuello del oponente desde guardia cerrada. Requiere gran flexibilidad.',                                            'https://www.youtube.com/watch?v=RJ7Iutti8cY', 'PUBLIC', NOW(), NOW(), 0),
(33, 1, 'Worm Guard',                'BOTTOM',         'Guardia de solapa: usa la propia solapa del gi del oponente para controlarlo. Solo gi. Creada por Keenan Cornelius.',                                    'https://www.youtube.com/watch?v=lLvkMU0xdHw', 'PUBLIC', NOW(), NOW(), 0),
(34, 1, 'Collar Sleeve Guard',       'BOTTOM',         'Un grip al cuello, otro a la manga. Guardia de distancia media. Transición a spider, lasso y DLR.',                                                     'https://www.youtube.com/watch?v=MJl8Wp2w3Lk', 'PUBLIC', NOW(), NOW(), 0),
(35, 1, 'Bottom Side Control',       'BOTTOM',         'Bajo el control lateral del oponente. Objetivo: recuperar guardia o tomar la espalda.',                                                                  'https://www.youtube.com/watch?v=5ALqUk9uefk', 'PUBLIC', NOW(), NOW(), 0),
(36, 1, 'Bottom Mount',              'BOTTOM',         'Debajo del mount del oponente. La peor posición del BJJ junto con bottom back mount.',                                                                   'https://www.youtube.com/watch?v=ypi3ie6hKTI', 'PUBLIC', NOW(), NOW(), 0),
(37, 1, 'Bottom Back Mount',         'BOTTOM',         'Con el oponente en nuestra espalda con ganchos. La posición más peligrosa y difícil de escapar.',                                                        'https://www.youtube.com/watch?v=N6lKNqUOZoY', 'PUBLIC', NOW(), NOW(), 0),
(38, 1, 'Turtle',                    'BOTTOM',         'Posición de tortuga defensiva: rodillas y codos en el suelo. Defensa temporal pero bajo ataque constante.',                                              'https://www.youtube.com/watch?v=as8eMNpFjPg', 'PUBLIC', NOW(), NOW(), 0),
(39, 1, 'Bottom Knee On Belly',      'BOTTOM',         'Bajo la rodilla en el abdomen del oponente. Posición incómoda y transitoria. Objetivo: escapar o recuperar guardia.',                                   'https://www.youtube.com/watch?v=BHUYEm0ve9A', 'PUBLIC', NOW(), NOW(), 0),
(40, 1, 'Submitted',                 'SUBMITTED',      'El luchador ha tapado. Fin del combate o round.',                                                                                                        NULL,                                          'PUBLIC', NOW(), NOW(), 0),
(41, 1, 'Sprawl',                    'STANDING',       'Defensa de derribo: caderas abajo y pies atrás para quitar la tracción al oponente que intenta double/single leg.',                                      'https://www.youtube.com/watch?v=Adz0whT8wBc', 'PUBLIC', NOW(), NOW(), 0),
(42, 1, 'Fireman Carry Position',    'STANDING',       'Control del hombro y pierna del oponente para la proyección de bombero. Gi y no-gi.',                                                                    'https://www.youtube.com/watch?v=71HjDPgZ5oE', 'PUBLIC', NOW(), NOW(), 0),
(43, 1, 'Collar Tie',                'STANDING',       'Control del cuello con una mano desde posición de pie. Base para snaps, underhooks y derribos de judo.',                                                'https://www.youtube.com/watch?v=MR1gQnRPZ_o', 'PUBLIC', NOW(), NOW(), 0),
(44, 1, 'Rear Standing',             'STANDING',       'Detrás del oponente de pie, sin ganchos aún. Transición a back mount o double underhook suplex.',                                                        'https://www.youtube.com/watch?v=rFIoeIB4-A4', 'PUBLIC', NOW(), NOW(), 0),
(45, 1, 'Technical Mount',           'TOP',            'Mount con una rodilla en el suelo y el otro pie plantado. Mayor estabilidad y control que mount estándar.',                                              'https://www.youtube.com/watch?v=DZ-fmNcJFg4', 'PUBLIC', NOW(), NOW(), 0),
(46, 1, 'Leg Knot',                  'TOP',            'Control de pierna desde top en leg entanglements. Inmovilización para ataques de kneebar o toe hold.',                                                   'https://www.youtube.com/watch?v=xWrEk9MbvUc', 'PUBLIC', NOW(), NOW(), 0),
(47, 1, 'Truck',                     'TOP',            'Posición 10th Planet: un gancho dentro de las piernas del oponente en turtle. Base para crotch ripper y back take.',                                    'https://www.youtube.com/watch?v=IY0CbahJG2A', 'PUBLIC', NOW(), NOW(), 0),
(48, 1, 'Mount with Arm Trap',       'TOP',            'Mount con el brazo del oponente atrapado bajo la rodilla. Maximiza el control antes de ataques al cuello.',                                             'https://www.youtube.com/watch?v=KPJJENQtRWU', 'PUBLIC', NOW(), NOW(), 0),
(49, 1, 'Reverse Scarf Hold',        'TOP',            'Kesa gatame invertido: cabeza controlada mirando hacia los pies. Ataques omoplata y americana invertida.',                                               'https://www.youtube.com/watch?v=XTRu2aRFwMM', 'PUBLIC', NOW(), NOW(), 0),
(50, 1, 'Modified Side Control',     'TOP',            'Side control con la cadera baja y el peso distribuido para resistir recuperaciones de guardia.',                                                         'https://www.youtube.com/watch?v=kWxijyG-6BE', 'PUBLIC', NOW(), NOW(), 0),
(51, 1, 'Dogfight',                  'TOP',            'Posición de batalla de rodillas: ambos en all-fours compitiendo underhooks. Transición a side control o back.',                                          'https://www.youtube.com/watch?v=p4zRBQwkmn4', 'PUBLIC', NOW(), NOW(), 0),
(52, 1, 'Inside Heel Hook Position', 'GROUND_NEUTRAL', 'Ashi garami con control interno para inside heel hook. Rodilla del oponente rotada hacia afuera.',                                                       'https://www.youtube.com/watch?v=5wvpttcNdMU', 'PUBLIC', NOW(), NOW(), 0),
(53, 1, 'Saddle',                    'GROUND_NEUTRAL', 'Honey hole / saddle: configuración de piernas para heel hooks con control superior del cuero. La más ventajosa.',                                        'https://www.youtube.com/watch?v=wnEuH8TDkZU', 'PUBLIC', NOW(), NOW(), 0),
(54, 1, 'Double Outside Ashi',       'GROUND_NEUTRAL', 'Ashi garami doble exterior. Presión extrema sobre ambas rodillas. Avanzado, sistema ADCC moderno.',                                                      'https://www.youtube.com/watch?v=eiI_4VBA-qA', 'PUBLIC', NOW(), NOW(), 0),
(55, 1, 'Front Headlock',            'GROUND_NEUTRAL', 'Control de cabeza frontal (no-gi). Base para guillotinas, darcé, anaconda y Peruvian necktie.',                                                          'https://www.youtube.com/watch?v=mCItPpw82nw', 'PUBLIC', NOW(), NOW(), 0),
(56, 1, 'Kimura Trap',               'GROUND_NEUTRAL', 'Brazo del oponente controlado en kimura trap. Sistema ofensivo que conecta múltiples posiciones top.',                                                   'https://www.youtube.com/watch?v=xyCakxmx-2E', 'PUBLIC', NOW(), NOW(), 0),
(57, 1, 'Squid Guard',               'BOTTOM',         'Variante avanzada de DLR con grip en el pantalón. Creada por Marcelo Garcia. Barridos y back takes.',                                                    'https://www.youtube.com/watch?v=5M1TLgoOBNU', 'PUBLIC', NOW(), NOW(), 0),
(58, 1, 'Shin-on-Shin Guard',        'BOTTOM',         'Espinilla contra espinilla del oponente. Guardia de entrada a SLX, DLR y barridos de tracción.',                                                         'https://www.youtube.com/watch?v=1bfW5_54U08', 'PUBLIC', NOW(), NOW(), 0),
(59, 1, 'Octopus Guard',             'BOTTOM',         'Control del brazo y pierna del mismo lado desde abajo. Back take y barridos usando el momentum del oponente.',                                           'https://www.youtube.com/watch?v=LQyn3FMkIto', 'PUBLIC', NOW(), NOW(), 0),
(60, 1, 'Mantis Guard',              'BOTTOM',         'Guardia con el pie en la cadera y el otro controlando la manga. Creada por Robson Moura. Barridos y triangles.',                                         'https://www.youtube.com/watch?v=0IWL67zu3s4', 'PUBLIC', NOW(), NOW(), 0),
(61, 1, 'Williams Guard',            'BOTTOM',         'Pierna enroscada al cuello del oponente con control de brazo. Sistema de Shawn Williams. No requiere solapa.',                                           'https://www.youtube.com/watch?v=1en94XB_2gE', 'PUBLIC', NOW(), NOW(), 0),
(62, 1, 'Coyote Guard',              'BOTTOM',         'DLR con el pie en el hueco de la rodilla del oponente. Barridos de arrastre y transiciones a leg locks.',                                                'https://www.youtube.com/watch?v=INqZhKrlNKk', 'PUBLIC', NOW(), NOW(), 0),
(63, 1, 'Inverted Guard',            'BOTTOM',         'Guardia invertida sobre los hombros mirando hacia abajo. Base para berimbolo y transiciones de leg lock.',                                               'https://www.youtube.com/watch?v=JuYWROW4MNc', 'PUBLIC', NOW(), NOW(), 0),
(64, 1, 'Half Butterfly Guard',      'BOTTOM',         'Combinación de half guard con un gancho mariposa. Versatilidad de ataques entre los dos sistemas.',                                                      'https://www.youtube.com/watch?v=a1x8n0QRl_c', 'PUBLIC', NOW(), NOW(), 0),
(65, 1, 'Seated Rear Guard',         'BOTTOM',         'Sentado con la espalda al oponente, gestionando el back mount antes de que inserte los ganchos.',                                                        'https://www.youtube.com/watch?v=d2n-R6yvw-g', 'PUBLIC', NOW(), NOW(), 0)
INSERT INTO technique (id, owner_id, name, category, description, youtube_url, minimum_belt, modality, start_position_id, end_position_id, visibility, family, created_at, updated_at, version) OVERRIDING SYSTEM VALUE VALUES
(1,  1, 'Rear Naked Choke',            'SUBMISSION', 'El estrangulamiento más importante del BJJ. Brazo rodeando el cuello con figura de 4. Ataca la arteria carótida.',                                                                                                 'https://www.youtube.com/watch?v=7TChXOpEx5M', 'WHITE',  'BOTH', 8,  40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(2,  1, 'Triangle Choke',              'SUBMISSION', 'Triángulo con las piernas atrapando cabeza y brazo del oponente. Estrangulación por compresión carotídea.',                                                                                                        'https://www.youtube.com/watch?v=20j7LcZ5xRY', 'WHITE',  'BOTH', 19, 40, 'PUBLIC', 'TRIANGLES',       NOW(), NOW(), 0),
(3,  1, 'Guillotine Choke',            'SUBMISSION', 'Estrangulación frontal con el brazo rodeando el cuello. Múltiples variantes: arm-in, high elbow, Marcelotine.',                                                                                                   'https://www.youtube.com/watch?v=KrZn5eJ-j4Q', 'WHITE',  'BOTH', 2,  40, 'PUBLIC', 'GUILLOTINES',     NOW(), NOW(), 0),
(4,  1, 'Bow and Arrow Choke',         'SUBMISSION', 'Estrangulación de espalda con grip en cuello y rodilla. La más efectiva desde back mount en gi.',                                                                                                                  'https://www.youtube.com/watch?v=xqNhZVNhxnE', 'BLUE',   'GI',   8,  40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(5,  1, 'Cross Collar Choke',          'SUBMISSION', 'Doble grip en las solapas cruzando las muñecas contra el cuello. Clásico del gi desde mount y guardia.',                                                                                                          'https://www.youtube.com/watch?v=9RBN_HVZ2OM', 'WHITE',  'GI',   6,  40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(6,  1, 'Baseball Bat Choke',          'SUBMISSION', 'Dos grips en el cuello en la misma dirección desde knee on belly o turtle. Gi. Rotación para aplicar.',                                                                                                           'https://www.youtube.com/watch?v=tc9RVnwKMlk', 'BLUE',   'GI',   11, 40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(7,  1, 'D''Arce Choke',               'SUBMISSION', 'Arm triangle con el brazo por debajo del cuello y sobre el brazo atrapado. Sin gi. Desde side control o turtle.',                                                                                                 'https://www.youtube.com/watch?v=8mGJh6sTgN8', 'BLUE',   'NOGI', 9,  40, 'PUBLIC', 'OTHER',           NOW(), NOW(), 0),
(8,  1, 'Anaconda Choke',              'SUBMISSION', 'Inverso del D''Arce: brazo por encima del cuello. Ataque rodando desde turtle. Muy usado en competición.',                                                                                                        'https://www.youtube.com/watch?v=OWVMvV4gmIo', 'BLUE',   'NOGI', 13, 40, 'PUBLIC', 'OTHER',           NOW(), NOW(), 0),
(9,  1, 'North-South Choke',           'SUBMISSION', 'Estrangulación desde north-south usando el brazo y el peso corporal contra el cuello.',                                                                                                                           'https://www.youtube.com/watch?v=HuwV3-g2knA', 'BLUE',   'NOGI', 10, 40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(10, 1, 'Ezekiel Choke',               'SUBMISSION', 'Estrangulación usando la manga del gi o la muñeca desde mount. Se puede aplicar con el oponente en guardia cerrada.',                                                                                             'https://www.youtube.com/watch?v=jIXrWitQZx4', 'WHITE',  'GI',   6,  40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(11, 1, 'Paper Cutter Choke',          'SUBMISSION', 'Estrangulación desde side control usando el antebrazo a través de la garganta con grip en el cuello lejano.',                                                                                                     'https://www.youtube.com/watch?v=P3BRaKQ0Hac', 'BLUE',   'GI',   9,  40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(12, 1, 'Clock Choke',                 'SUBMISSION', 'Estrangulación rotacional desde turtle: grip en el cuello lejano, rodar como las agujas del reloj.',                                                                                                              'https://www.youtube.com/watch?v=QJuyXdkYhm8', 'BLUE',   'GI',   13, 40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(13, 1, 'Loop Choke',                  'SUBMISSION', 'Estrangulación sorpresa desde guardia: un grip en el cuello con la cabeza bajo la axila. Gi.',                                                                                                                    'https://www.youtube.com/watch?v=P3BRaKQ0Hac', 'BLUE',   'GI',   19, 40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(14, 1, 'Peruvian Necktie',            'SUBMISSION', 'Variante de guillotine con las piernas sobre los hombros del oponente. Front headlock. Sin gi.',                                                                                                                  'https://www.youtube.com/watch?v=6GUtd52rdzY', 'BLUE',   'NOGI', 13, 40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(15, 1, 'Armbar',                      'SUBMISSION', 'Hiperextensión del codo. El armbar más importante del BJJ. Aplicable desde mount, guardia, back mount y muchas otras posiciones.',                                                                                'https://www.youtube.com/watch?v=hDmXQz0JT-8', 'WHITE',  'BOTH', 19, 40, 'PUBLIC', 'ARMBARS',         NOW(), NOW(), 0),
(16, 1, 'Kimura',                      'SUBMISSION', 'Llave de hombro con figura de 4 en el brazo. Aplicable desde side control, guardia, half guard y standing.',                                                                                                      'https://www.youtube.com/watch?v=p-6lmaseoGI', 'WHITE',  'BOTH', 9,  40, 'PUBLIC', 'SHOULDER_LOCKS',  NOW(), NOW(), 0),
(17, 1, 'Americana',                   'SUBMISSION', 'Reverso del kimura. Empuja la muñeca hacia el suelo mientras levanta el codo. Desde side control y mount.',                                                                                                       'https://www.youtube.com/watch?v=vJ5EOWy5C2o', 'WHITE',  'BOTH', 9,  40, 'PUBLIC', 'SHOULDER_LOCKS',  NOW(), NOW(), 0),
(18, 1, 'Omoplata',                    'SUBMISSION', 'Llave de hombro usando las piernas. La pierna atrapa el brazo y el cuerpo rota para aplicar la llave.',                                                                                                           'https://www.youtube.com/watch?v=AyqD_5qtZTY', 'WHITE',  'BOTH', 19, 40, 'PUBLIC', 'SHOULDER_LOCKS',  NOW(), NOW(), 0),
(19, 1, 'Wristlock',                   'SUBMISSION', 'Ataque a la articulación de la muñeca. Cuatro variantes: compresión, extensión, rotación interna y externa.',                                                                                                     'https://www.youtube.com/watch?v=Wr0EjCPOC9Y', 'BLUE',   'BOTH', 9,  40, 'PUBLIC', 'SHOULDER_LOCKS',  NOW(), NOW(), 0),
(20, 1, 'Baratoplata',                 'SUBMISSION', 'Llave de hombro tipo kimura usando piernas y caderas. Sigue a un triángulo. Popularizado por Braulio Estima.',                                                                                                    'https://www.youtube.com/watch?v=PgFUi7mMeIo', 'PURPLE', 'BOTH', 19, 40, 'PUBLIC', 'ARMBARS',         NOW(), NOW(), 0),
(21, 1, 'Gogoplata',                   'SUBMISSION', 'Omoplata con el pie en la garganta del oponente. Requiere gran flexibilidad. Sistema rubber guard.',                                                                                                              'https://www.youtube.com/watch?v=PsYSobSqBgI', 'BLUE',   'BOTH', 32, 40, 'PUBLIC', 'ARMBARS',         NOW(), NOW(), 0),
(22, 1, 'Straight Ankle Lock',         'SUBMISSION', 'Llave de tobillo recta: pie en la axila, caderas extendidas. Legal en todos los cinturones.',                                                                                                                     'https://www.youtube.com/watch?v=5ZAqUQpsus8', 'WHITE',  'BOTH', 30, 40, 'PUBLIC', 'LEG_ENTANGLEMENT',NOW(), NOW(), 0),
(23, 1, 'Inside Heel Hook',            'SUBMISSION', 'Torsión del talón hacia adentro atacando el ligamento externo de la rodilla. IBJJF No-Gi: permitido desde brown belt. Permitido desde blanco en ADCC, EBI y la mayoría de torneos de grappling open.',           'https://www.youtube.com/watch?v=w-W0ug7Edag', 'BROWN',  'NOGI', 30, 40, 'PUBLIC', 'LEG_ENTANGLEMENT',NOW(), NOW(), 0),
(24, 1, 'Outside Heel Hook',           'SUBMISSION', 'Torsión del talón hacia afuera atacando los ligamentos internos de la rodilla. El más peligroso de los leg locks. IBJJF No-Gi: permitido desde brown belt. Prohibido en Gi en todas las federaciones importantes.','https://www.youtube.com/watch?v=zQ-FNH5a01k', 'BROWN',  'NOGI', 17, 40, 'PUBLIC', 'LEG_ENTANGLEMENT',NOW(), NOW(), 0),
(25, 1, 'Kneebar',                     'SUBMISSION', 'Hiperextensión de rodilla aislando la pierna entre el cuerpo. IBJJF: legal desde purple belt (Gi y No-Gi). Ataque desde leg entanglement, mount o top half guard.',                                              'https://www.youtube.com/watch?v=oBlMI4iKm3c', 'PURPLE', 'BOTH', 15, 40, 'PUBLIC', 'LEG_ENTANGLEMENT',NOW(), NOW(), 0),
(26, 1, 'Toe Hold',                    'SUBMISSION', 'Rotación del tobillo atacando los ligamentos del pie y tobillo. IBJJF: legal desde blue belt (Gi y No-Gi). Requiere control de pierna previo.',                                                                   'https://www.youtube.com/watch?v=7wVbUS0jCts', 'BLUE',   'BOTH', 15, 40, 'PUBLIC', 'LEG_ENTANGLEMENT',NOW(), NOW(), 0),
(27, 1, 'Calf Slicer',                 'SUBMISSION', 'Compresión del gemelo: espinilla o antebrazo detrás de la rodilla doblando la pierna sobre sí misma. IBJJF: legal desde purple belt (Gi y No-Gi).',                                                               'https://www.youtube.com/watch?v=YVfHVbGX5OA', 'PURPLE', 'BOTH', 15, 40, 'PUBLIC', 'LEG_ENTANGLEMENT',NOW(), NOW(), 0),
(28, 1, 'Bicep Slicer',                'SUBMISSION', 'Compresión del bíceps: antebrazo o espinilla en el pliegue del codo forzando hiperextensión. IBJJF: legal desde brown belt (Gi y No-Gi).',                                                                        'https://www.youtube.com/watch?v=bt_hFveUzzI', 'BROWN',  'BOTH', 19, 40, 'PUBLIC', 'SHOULDER_LOCKS',  NOW(), NOW(), 0),
(29, 1, 'Estima Lock',                 'SUBMISSION', 'Lock de tobillo en rotación externa desde posición top. Prohibido en competición Gi IBJJF. Usado principalmente en grappling No-Gi y submission-only.',                                                           'https://www.youtube.com/watch?v=vRWqSjmhBYI', 'BROWN',  'BOTH', 19, 40, 'PUBLIC', 'SHOULDER_LOCKS',  NOW(), NOW(), 0),
(30, 1, 'Electric Chair',              'SUBMISSION', 'Separación de las piernas del oponente desde lockdown/dogbar half guard, atacando la ingle y espalda baja. IBJJF: no tiene restricción específica, se trata como leg entanglement. Aplicable desde purple belt.',  'https://www.youtube.com/watch?v=YVfHVbGX5OA', 'PURPLE', 'BOTH', 23, 40, 'PUBLIC', 'LEG_ENTANGLEMENT',NOW(), NOW(), 0),
(31, 1, 'Scissor Sweep',               'TAKEDOWN',   'Movimiento en tijera desde guardia cerrada. Se carga al oponente en la rodilla y se hace palanca con las piernas en oposición.',                                                                                   'https://www.youtube.com/watch?v=UBf7uF5x8GQ', 'WHITE',  'BOTH', 19, 6,  'PUBLIC', 'CLOSED_GUARD',    NOW(), NOW(), 0),
(32, 1, 'Hip Bump Sweep',              'TAKEDOWN',   'Explosión de cadera desde guardia cerrada. Se sienta hacia adelante usando el momentum de cadera para voltear.',                                                                                                   'https://www.youtube.com/watch?v=86eSdQYSjxA', 'WHITE',  'BOTH', 19, 6,  'PUBLIC', 'SWEEPS',          NOW(), NOW(), 0),
(33, 1, 'Flower Sweep',                'TAKEDOWN',   'Barrido pendular desde guardia cerrada. Grip en manga y pantalón, movimiento pendular de la pierna libre para voltear.',                                                                                           'https://www.youtube.com/watch?v=hCjf78aGqQI', 'WHITE',  'BOTH', 19, 6,  'PUBLIC', 'CLOSED_GUARD',    NOW(), NOW(), 0),
(34, 1, 'Butterfly Sweep',             'TAKEDOWN',   'Barrido con ganchos mariposa. Underhook + gancho del pie para levantar y voltear. Muy efectivo en no-gi.',                                                                                                         'https://www.youtube.com/watch?v=x7Wv0w9EEcc', 'WHITE',  'BOTH', 24, 6,  'PUBLIC', 'BUTTERFLY_GUARD', NOW(), NOW(), 0),
(35, 1, 'Elevator Sweep',              'TAKEDOWN',   'Barrido desde half guard usando el gancho interior como ascensor para levantar la pierna del oponente.',                                                                                                           'https://www.youtube.com/watch?v=awCHI_VFJQI', 'WHITE',  'BOTH', 20, 6,  'PUBLIC', 'BUTTERFLY_GUARD', NOW(), NOW(), 0),
(36, 1, 'Old School Sweep',            'TAKEDOWN',   'Sweep clásico desde half guard: underhook, control del pie, sacar el pie y rodar. Muy básico y efectivo.',                                                                                                         'https://www.youtube.com/watch?v=b83nf7GRLCU', 'WHITE',  'BOTH', 20, 9,  'PUBLIC', 'HALF_GUARD',      NOW(), NOW(), 0),
(37, 1, 'De La Riva Sweep',            'TAKEDOWN',   'Barrido clásico desde DLR: empujar con el pie del gancho, tirar del tobillo, rodar hacia el lado contrario.',                                                                                                      'https://www.youtube.com/watch?v=J8QJ3tOEBsY', 'WHITE',  'GI',   25, 9,  'PUBLIC', 'DLR_GUARD',       NOW(), NOW(), 0),
(38, 1, 'Spider Guard Sweep',          'TAKEDOWN',   'Barrido desde spider guard: empujar un bíceps con el pie mientras se jala la manga contraria para desequilibrar.',                                                                                                 'https://www.youtube.com/watch?v=ZvhT-y88kk8', 'WHITE',  'GI',   27, 9,  'PUBLIC', 'OPEN_GUARD',      NOW(), NOW(), 0),
(39, 1, 'X-Guard Sweep',               'TAKEDOWN',   'Elevación desde X-guard para tirar al oponente hacia atrás o lateral. Technical stand o proyección.',                                                                                                             'https://www.youtube.com/watch?v=oe-xUmRLcUg', 'WHITE',  'BOTH', 29, 9,  'PUBLIC', 'LEG_ENTANGLEMENT',NOW(), NOW(), 0),
(40, 1, 'Single Leg X Sweep',          'TAKEDOWN',   'Barrido desde ashi garami/SLX. Múltiples variantes: back sweep, outside sweep, technical stand.',                                                                                                                 'https://www.youtube.com/watch?v=9z4WRGQ71bI', 'WHITE',  'BOTH', 30, 9,  'PUBLIC', 'LEG_ENTANGLEMENT',NOW(), NOW(), 0),
(41, 1, 'Lasso Pendulum Sweep',        'TAKEDOWN',   'Combinación de lasso guard y movimiento pendular para voltear al oponente. Solo gi.',                                                                                                                              'https://www.youtube.com/watch?v=RAQiYBz0FiQ', 'WHITE',  'GI',   28, 6,  'PUBLIC', 'OPEN_GUARD',      NOW(), NOW(), 0),
(42, 1, 'Berimbolo Back Take',         'TAKEDOWN',   'Inversión desde DLR para rodar por debajo y tomar la espalda. Movimiento icónico del BJJ moderno.',                                                                                                               'https://www.youtube.com/watch?v=UyHxmqJi4Pc', 'WHITE',  'GI',   25, 8,  'PUBLIC', 'BACK_TAKES',      NOW(), NOW(), 0),
(43, 1, 'Deep Half Sweep',             'TAKEDOWN',   'Barrido desde deep half guard pasando por debajo para voltear al oponente y quedar encima.',                                                                                                                      'https://www.youtube.com/watch?v=OZ8sfB4SLuE', 'WHITE',  'BOTH', 22, 9,  'PUBLIC', 'HALF_GUARD',      NOW(), NOW(), 0),
(44, 1, 'Waiter Sweep',                'TAKEDOWN',   'Sweep desde half guard inspirado en el gesto de mesero: elevar la pierna del oponente con el pie interior.',                                                                                                       'https://www.youtube.com/watch?v=N4-J1j1JNv8', 'WHITE',  'BOTH', 20, 9,  'PUBLIC', 'SWEEPS',          NOW(), NOW(), 0),
(45, 1, 'John Wayne Sweep',            'TAKEDOWN',   'Sweep desde half guard estirando la pierna del oponente lateralmente. Variante del sistema de half guard.',                                                                                                        'https://www.youtube.com/watch?v=wN4gXJSAGoA', 'WHITE',  'BOTH', 20, 9,  'PUBLIC', 'OPEN_GUARD',      NOW(), NOW(), 0),
(46, 1, 'Tripod Sweep',                'TAKEDOWN',   'Barrido desde open guard: un pie en la cadera, otro enganchando el tobillo, jalando la manga hacia abajo.',                                                                                                       'https://www.youtube.com/watch?v=4ICUXPjKIBk', 'WHITE',  'GI',   18, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(47, 1, 'Sickle Sweep',                'TAKEDOWN',   'Variante del tripod sweep con el pie barriendo el tobillo del oponente en arco. Desde seated guard.',                                                                                                             'https://www.youtube.com/watch?v=ZL1iqyD4EIg', 'WHITE',  'BOTH', 18, 9,  'PUBLIC', 'SWEEPS',          NOW(), NOW(), 0),
(48, 1, 'Knee Shield Sweep',           'TAKEDOWN',   'Sweep desde Z-guard usando el escudo de rodilla para crear distancia y voltear con underhook.',                                                                                                                   'https://www.youtube.com/watch?v=xGLDU3qLBr0', 'WHITE',  'BOTH', 21, 9,  'PUBLIC', 'HALF_GUARD',      NOW(), NOW(), 0),
(49, 1, 'Torreando Pass',              'PASS',       'Pase de velocidad jalando ambas piernas a un lado y pasando rápidamente a side control. El más fundamental del BJJ.',                                                                                              'https://www.youtube.com/watch?v=bqilRrhC96c', 'WHITE',  'BOTH', 18, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(50, 1, 'Knee Slice Pass',             'PASS',       'La rodilla corta diagonalmente el muslo del oponente. El pase más versátil y de mayor porcentaje en gi y no-gi.',                                                                                                  'https://www.youtube.com/watch?v=jiBiDvrz9iw', 'WHITE',  'BOTH', 20, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(51, 1, 'Leg Drag Pass',               'PASS',       'Arrastra la pierna del oponente cruzando su cadera. Connector entre passing externo y passing de presión.',                                                                                                       'https://www.youtube.com/watch?v=n596l_pJi-E', 'WHITE',  'BOTH', 25, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(52, 1, 'Over-Under Pass',             'PASS',       'Un brazo por encima de una pierna, otro por debajo de la otra. Presión máxima sobre las caderas del oponente.',                                                                                                   'https://www.youtube.com/watch?v=4hAY12ghrGk', 'WHITE',  'BOTH', 19, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(53, 1, 'Double Under Pass',           'PASS',       'Ambos brazos por debajo de ambas piernas. Stack y presión hacia la cabeza del oponente para pasar.',                                                                                                              'https://www.youtube.com/watch?v=PizdshB63kw', 'WHITE',  'BOTH', 19, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(54, 1, 'Smash Pass',                  'PASS',       'Pase de presión aplastando las piernas del oponente con el peso corporal. No-gi. Muy popular en competición.',                                                                                                    'https://www.youtube.com/watch?v=5WGF7pIe7as', 'WHITE',  'NOGI', 24, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(55, 1, 'Body Lock Pass',              'PASS',       'Abrazo de caderas cerrado (no-gi). El estándar del high-level no-gi moderno. Dominado por Gordon Ryan.',                                                                                                          'https://www.youtube.com/watch?v=kJCTVKJR5AM', 'WHITE',  'NOGI', 18, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(56, 1, 'X-Pass',                      'PASS',       'Control rápido de una rodilla y cadera para pasar. Velocidad y timing antes que fuerza.',                                                                                                                         'https://www.youtube.com/watch?v=m6HMbS1mnkE', 'WHITE',  'BOTH', 18, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(57, 1, 'Long Step Pass',              'PASS',       'Paso largo hacia atrás para liberar la pierna de la guardia y pasar. Efectivo contra guardia cerrada y media guardia.',                                                                                            'https://www.youtube.com/watch?v=hE_hHGcKvHc', 'WHITE',  'BOTH', 19, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(58, 1, 'Float Pass',                  'PASS',       'Pase flotante usando timing y equilibrio sin presionar. Popularizado por Danaher/Gordon Ryan contra guardias pegajosas.',                                                                                          'https://www.youtube.com/watch?v=UiFpG9mV5Sg', 'WHITE',  'BOTH', 25, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(59, 1, 'Backstep Pass',               'PASS',       'Paso atrás sobre la pierna del oponente para pasar. Muy efectivo contra DLR y guardias abiertas.',                                                                                                                'https://www.youtube.com/watch?v=ibnsTuuKrLU', 'WHITE',  'BOTH', 25, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(60, 1, 'Running Pass',                'PASS',       'Rueda lateral o carrera alrededor de la guardia del oponente. Requiere espacio y velocidad.',                                                                                                                     'https://www.youtube.com/watch?v=WeFjJAGZJnA', 'WHITE',  'BOTH', 27, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(61, 1, 'Half Guard Pass',             'PASS',       'Pase de media guardia usando crossface y presión para liberar la pierna atrapada.',                                                                                                                               'https://www.youtube.com/watch?v=KuPVJovimxo', 'WHITE',  'BOTH', 20, 9,  'PUBLIC', 'HALF_GUARD',      NOW(), NOW(), 0),
(62, 1, 'Leg Weave Pass',              'PASS',       'Teje el brazo debajo de la pierna conectando al cuello. Pase de presión desde closed guard y half guard.',                                                                                                        'https://www.youtube.com/watch?v=4C28aCPlR60', 'WHITE',  'GI',   20, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(63, 1, 'Sao Paulo Pass',              'PASS',       'Pase gi usando el lapel cruzado por debajo de la pierna para fijarla. Variante del over-under.',                                                                                                                  'https://www.youtube.com/watch?v=1n1SsW3NGeY', 'WHITE',  'GI',   19, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(64, 1, 'Torreando to Mount',          'PASS',       'Variante del torreando que termina directamente en mount saltando la fase de side control.',                                                                                                                      'https://www.youtube.com/watch?v=EYJJEOqbqzA', 'WHITE',  'BOTH', 18, 6,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(65, 1, 'Shin Slide Pass',             'PASS',       'Espinilla deslizando sobre el muslo del oponente para pasar. Variante del knee slice.',                                                                                                                           'https://www.youtube.com/watch?v=LN7vQbV6R8U', 'WHITE',  'BOTH', 20, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(66, 1, 'Wilson Pass',                 'PASS',       'Pase de presión usando el hombro en la cadera del oponente. Grinding y lento pero muy efectivo.',                                                                                                                 'https://www.youtube.com/watch?v=jqPuGmXz3Ms', 'WHITE',  'BOTH', 20, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(67, 1, 'Double Leg Takedown',         'TAKEDOWN',   'Derribo de lucha libre clásico: agarre de ambas piernas, empuje con el hombro en la cadera.',                                                                                                                     'https://www.youtube.com/watch?v=4DHzLvLd-0Y', 'WHITE',  'BOTH', 1,  9,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(68, 1, 'Single Leg Takedown',         'TAKEDOWN',   'Derribo agarrando una sola pierna. Múltiples variantes de terminación: run the pipe, high crotch, trip.',                                                                                                         'https://www.youtube.com/watch?v=4HBVdF5AXc0', 'WHITE',  'BOTH', 1,  9,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(69, 1, 'Ankle Pick',                  'TAKEDOWN',   'Derribo de bajo riesgo: jalar el tobillo mientras se empuja el hombro. Muy común en BJJ por su seguridad.',                                                                                                       'https://www.youtube.com/watch?v=Bz8H8bVWA7k', 'WHITE',  'BOTH', 2,  9,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(70, 1, 'Arm Drag to Back Take',       'TAKEDOWN',   'Arrastre de brazo de pie para tomar la espalda de pie o llevar al suelo en back mount.',                                                                                                                          'https://www.youtube.com/watch?v=6a7xCbL4e9k', 'WHITE',  'BOTH', 5,  8,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0)
INSERT INTO technique (id, owner_id, name, category, description, youtube_url, minimum_belt, modality, start_position_id, end_position_id, visibility, family, created_at, updated_at, version) OVERRIDING SYSTEM VALUE VALUES
(71,  1, 'Hip Throw',                  'TAKEDOWN',   'Proyección de judo básica usando la cadera como pivote (O-Goshi). La más enseñada a principiantes.',                                                                                      'https://www.youtube.com/watch?v=lV59S5JADbQ', 'WHITE',  'BOTH', 2,  9,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(72,  1, 'Shoulder Throw',             'TAKEDOWN',   'Proyección de hombro de judo (Seoi Nage). Muy efectiva cuando el oponente empuja. Gi y no-gi.',                                                                                           'https://www.youtube.com/watch?v=ey3VCTdxBYU', 'WHITE',  'BOTH', 2,  9,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(73,  1, 'Harai Goshi',                'TAKEDOWN',   'Proyección de judo barriendo la cadera del oponente. Una de las proyecciones más antiguas del Kodokan.',                                                                                  'https://www.youtube.com/watch?v=w4dPmS8JlaI', 'WHITE',  'GI',   2,  9,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(74,  1, 'Foot Sweep',                 'TAKEDOWN',   'Barrido de pie interno (O-Uchi Gari). Derribo de bajo riesgo muy usado en BJJ. Funciona en gi y no-gi.',                                                                                  'https://www.youtube.com/watch?v=B8oKkgOmITk', 'WHITE',  'BOTH', 2,  9,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(75,  1, 'Kouchi Gari',                'TAKEDOWN',   'Barrido de pie menor interno. Barre el pie delantero del oponente hacia adentro.',                                                                                                        'https://www.youtube.com/watch?v=1FZ8Iid5YFY', 'WHITE',  'GI',   2,  9,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(76,  1, 'Snap Down',                  'TAKEDOWN',   'Snap del cuello hacia abajo para hacer turtle al oponente. Base para guillotina o anaconda.',                                                                                             'https://www.youtube.com/watch?v=7G9G5MVkG1c', 'WHITE',  'NOGI', 2,  13, 'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(77,  1, 'Sacrifice Throw',            'TAKEDOWN',   'Proyección de sacrificio (Tomoe Nage): caer de espaldas y proyectar al oponente por encima. Gi. Alto riesgo/recompensa.',                                                                 'https://www.youtube.com/watch?v=pAzqmJOinAU', 'WHITE',  'GI',   2,  6,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(78,  1, 'Guard Pull',                 'TAKEDOWN',   'Sentarse a guardia intencionalmente. Técnica controvertida pero muy usada en competición de gi.',                                                                                          'https://www.youtube.com/watch?v=KFLX_FhYh1o', 'WHITE',  'GI',   1,  19, 'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(79,  1, 'Bridge and Roll',            'ESCAPE',     'Puente y rodillo desde bottom mount (Upa). Bridge explosivo al lado donde el brazo está atrapado para volcar.',                                                                            'https://www.youtube.com/watch?v=UyxNPnR24hE', 'WHITE',  'BOTH', 36, 19, 'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(80,  1, 'Elbow-Knee Escape',          'ESCAPE',     'Escape codo-rodilla desde mount usando el movimiento de gambas (shrimp). Recupera guardia media o cerrada.',                                                                              'https://www.youtube.com/watch?v=SYel-mVSMAI', 'WHITE',  'BOTH', 36, 20, 'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(81,  1, 'Side Control Knee-In',       'ESCAPE',     'Insertar la rodilla desde bottom side control usando bridge+shrimp. Recuperar guardia es la clave.',                                                                                      'https://www.youtube.com/watch?v=xOidpN1G-Tk', 'WHITE',  'BOTH', 35, 20, 'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(82,  1, 'Ghost Escape',               'ESCAPE',     'Escapar hacia atrás desde side control como fantasma: rodar el hombro por debajo del oponente.',                                                                                         'https://www.youtube.com/watch?v=t13VFvRh5lo', 'WHITE',  'BOTH', 35, 20, 'PUBLIC', 'OTHER',           NOW(), NOW(), 0),
(83,  1, 'Back Escape',                'ESCAPE',     'Escapar del back mount: bajar el gancho superior, defender el cuello con dos manos y rodar hacia un lado.',                                                                               'https://www.youtube.com/watch?v=N6lKNqUOZoY', 'WHITE',  'BOTH', 37, 9,  'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(84,  1, 'Turtle Guard Recovery',      'ESCAPE',     'Rodar desde turtle para recuperar guardia. Múltiples opciones: rodar adelante, atrás o lateral.',                                                                                         'https://www.youtube.com/watch?v=H1KGOimsBFU', 'WHITE',  'BOTH', 38, 19, 'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(85,  1, 'North-South Escape',         'ESCAPE',     'Escapar desde north-south: girar los hombros y recuperar guardia lateral o media guardia.',                                                                                               'https://www.youtube.com/watch?v=G6f0VK9T1ks', 'WHITE',  'BOTH', 35, 20, 'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(86,  1, 'Kimura Defense to Guard',    'ESCAPE',     'Defender kimura desde side control y convertirla en oportunidad de recuperar guardia.',                                                                                                   'https://www.youtube.com/watch?v=wWq5mJeP_0M', 'WHITE',  'BOTH', 35, 20, 'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(87,  1, 'Knee On Belly Escape',       'ESCAPE',     'Escapar de knee on belly: crear espacio, introducir guardia o rodar hacia los pies del oponente.',                                                                                        'https://www.youtube.com/watch?v=MYi37y_x5TM', 'WHITE',  'BOTH', 39, 20, 'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(88,  1, 'Armbar Defense',             'ESCAPE',     'Defender el armbar: stacking, voltear, interlazar los dedos. Recuperar guardia o posición top.',                                                                                          'https://www.youtube.com/watch?v=0r-6K1UoLnU', 'WHITE',  'BOTH', 19, 9,  'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(89,  1, 'Triangle Defense',           'ESCAPE',     'Defender el triángulo: stack + postura, voltear, salir hacia el pasador.',                                                                                                                'https://www.youtube.com/watch?v=iknZhK5cNZg', 'WHITE',  'BOTH', 19, 9,  'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(90,  1, 'Heel Hook Defense',          'ESCAPE',     'Defensa urgente de heel hook: no rotar la rodilla, alinear caderas con el talón, vine escape o back step para liberar. Necesaria desde cinturón blanco en competición No-Gi.',            'https://www.youtube.com/watch?v=3CmHYtQhbRk', 'WHITE',  'NOGI', 15, 1,  'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(91,  1, 'Mount to Back Take',         'TRANSITION', 'Tomar la espalda desde mount cuando el oponente se voltea intentando escapar. Seguir el movimiento.',                                                                                     'https://www.youtube.com/watch?v=bm4OLGPQZTU', 'WHITE',  'BOTH', 6,  8,  'PUBLIC', 'BACK_TAKES',      NOW(), NOW(), 0),
(92,  1, 'Side Control to Mount',      'TRANSITION', 'Avanzar de side control a mount: knee slide, step over o técnica de rodilla.',                                                                                                            'https://www.youtube.com/watch?v=_M3PEFLbcMs', 'WHITE',  'BOTH', 9,  6,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(93,  1, 'Side Control to Back Take',  'TRANSITION', 'Tomar la espalda desde side control cuando el oponente se voltea hacia la turtle.',                                                                                                       'https://www.youtube.com/watch?v=RR8UfHJkxHg', 'WHITE',  'BOTH', 9,  8,  'PUBLIC', 'BACK_TAKES',      NOW(), NOW(), 0),
(94,  1, 'Guard to Back Take',         'TRANSITION', 'Transición de cualquier guardia a toma de espalda. Desde closed guard, butterfly, X-guard.',                                                                                              'https://www.youtube.com/watch?v=J3eN3p1KDNE', 'WHITE',  'BOTH', 19, 8,  'PUBLIC', 'BACK_TAKES',      NOW(), NOW(), 0),
(95,  1, 'Side Control to North-South','TRANSITION', 'Girar de side control a north-south para cambiar ángulo de ataque o presión.',                                                                                                            'https://www.youtube.com/watch?v=qKqEFOLJqX0', 'WHITE',  'BOTH', 9,  10, 'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(96,  1, 'DLR to Single Leg X',        'TRANSITION', 'Transición de DLR a SLX (ashi garami). Girar por debajo para re-enredar la pierna.',                                                                                                      'https://www.youtube.com/watch?v=VKhiHZv1R7o', 'WHITE',  'BOTH', 25, 30, 'PUBLIC', 'LEG_ENTANGLEMENT',NOW(), NOW(), 0),
