(98,  1, 'Closed Guard to Butterfly',  'TRANSITION', 'Abrir la guardia cerrada y reconfigurar los ganchos para guardia mariposa.',                                                                                                              'https://www.youtube.com/watch?v=5eE7jkxBLKQ', 'WHITE',  'BOTH', 19, 24, 'PUBLIC', 'BUTTERFLY_GUARD', NOW(), NOW(), 0),
(99,  1, 'Mount to Knee On Belly',     'TRANSITION', 'Pasar de mount a knee on belly para cambiar el ángulo o presionar diferente.',                                                                                                            'https://www.youtube.com/watch?v=t2kSoJkMiNI', 'WHITE',  'BOTH', 6,  11, 'PUBLIC', 'OTHER',           NOW(), NOW(), 0),
