(102, 1, 'Turtle to Guard Recovery',   'TRANSITION', 'Desde turtle rodar hacia adelante para recuperar guardia antes de que el oponente tome la espalda.',                                                                                      'https://www.youtube.com/watch?v=oPV0mJMD9Xw', 'WHITE',  'BOTH', 38, 19, 'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(103, 1, 'Arm-In Guillotine',          'SUBMISSION', 'Guillotina con el brazo del oponente atrapado dentro. Más segura que la guillotina clásica. Muy popular en no-gi.',                                                                       'https://www.youtube.com/watch?v=RW7Q0rcxXpg', 'BLUE',   'NOGI', 19, 40, 'PUBLIC', 'GUILLOTINES',     NOW(), NOW(), 0),
(104, 1, 'High Elbow Guillotine',      'SUBMISSION', 'Variante de guillotina con el codo elevado para maximizar la presión. Dominada por Marcelo Garcia. Letal en competición.',                                                                'https://www.youtube.com/watch?v=RW7Q0rcxXpg', 'BLUE',   'NOGI', 19, 40, 'PUBLIC', 'GUILLOTINES',     NOW(), NOW(), 0),
(105, 1, 'Marcelotine',                'SUBMISSION', 'Guillotina sin el brazo con el codo cruzando por encima del hombro. Variante de Marcelo Garcia de máxima eficacia.',                                                                      'https://www.youtube.com/watch?v=RW7Q0rcxXpg', 'PURPLE', 'NOGI', 19, 40, 'PUBLIC', 'GUILLOTINES',     NOW(), NOW(), 0),
(106, 1, 'Von Flue Choke',             'SUBMISSION', 'Estrangulación de contraataque a guillotina: bajar el hombro contra el cuello del oponente que intenta guillotina.',                                                                      'https://www.youtube.com/watch?v=RW7Q0rcxXpg', 'PURPLE', 'NOGI', 9,  40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(107, 1, 'Lapel Choke',                'SUBMISSION', 'Estrangulación usando la solapa del gi. Grip en solapa propia o del oponente. Múltiples variantes según posición.',                                                                        'https://www.youtube.com/watch?v=xLLYpOsq6GQ', 'BLUE',   'GI',   8,  40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(108, 1, 'Brabo Choke',                'SUBMISSION', 'Estrangulación usando la solapa para crear el efecto de guillotina. Gi. También llamado loop choke con solapa.',                                                                          'https://www.youtube.com/watch?v=P3BRaKQ0Hac', 'BLUE',   'GI',   9,  40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(109, 1, 'Twister',                    'SUBMISSION', 'Torsión espinal desde control lateral de espalda. Icónico del sistema 10th Planet de Eddie Bravo. Muy raro en competición.',                                                               'https://www.youtube.com/watch?v=QvRmTGSGMoE', 'BROWN',  'NOGI', 8,  40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(110, 1, 'Arm Triangle Choke',         'SUBMISSION', 'Estrangulación triángulo con los brazos atrapando cabeza y hombro. Desde mount o side control. Muy efectiva en MMA.',                                                                     'https://www.youtube.com/watch?v=5WGoJMGiKm4', 'BLUE',   'BOTH', 6,  40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(111, 1, 'Scarf Choke',                'SUBMISSION', 'Estrangulación desde kesa gatame usando el peso del cuerpo sobre el cuello. Gi y no-gi. Difícil de defender.',                                                                            'https://www.youtube.com/watch?v=rlV8UqBiMaw', 'BLUE',   'BOTH', 12, 40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
