(113, 1, 'Bread Cutter Choke',         'SUBMISSION', 'Estrangulación desde half guard top cortando el cuello con el antebrazo. Gi. Muy eficaz con crossface.',                                                                                  'https://www.youtube.com/watch?v=P3BRaKQ0Hac', 'BLUE',   'GI',   20, 40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(114, 1, 'Mounted Triangle',           'SUBMISSION', 'Triángulo desde mount: piernas alrededor del cuello y brazo del oponente. Muy difícil de escapar para el oponente.',                                                                       'https://www.youtube.com/watch?v=K8oMSsPJnGk', 'PURPLE', 'BOTH', 6,  40, 'PUBLIC', 'TRIANGLES',       NOW(), NOW(), 0),
(115, 1, 'Reverse Triangle',           'SUBMISSION', 'Triángulo invertido con piernas alrededor del cuello en posición opuesta. Desde north-south o turtle top.',                                                                               'https://www.youtube.com/watch?v=K8oMSsPJnGk', 'PURPLE', 'BOTH', 10, 40, 'PUBLIC', 'TRIANGLES',       NOW(), NOW(), 0),
(116, 1, 'Arm Crush',                  'SUBMISSION', 'Compresión del brazo atrapado desde mount usando el peso del cuerpo. Variante de keylock sin grip en la mano.',                                                                           'https://www.youtube.com/watch?v=vJ5EOWy5C2o', 'WHITE',  'BOTH', 6,  40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(117, 1, 'Monoplata',                  'SUBMISSION', 'Omoplata invertida con el oponente en posición opuesta. Difícil de configurar pero muy inesperada.',                                                                                       'https://www.youtube.com/watch?v=PgFUi7mMeIo', 'BROWN',  'BOTH', 9,  40, 'PUBLIC', 'ARMBARS',         NOW(), NOW(), 0),
(118, 1, 'Armbar from Mount',          'SUBMISSION', 'Armbar clásico desde mount: levantar la cadera, rotar sobre el brazo y extender las caderas. El más fundamental.',                                                                        'https://www.youtube.com/watch?v=xQ_pN7KZkqk', 'WHITE',  'BOTH', 6,  40, 'PUBLIC', 'ARMBARS',         NOW(), NOW(), 0),
(119, 1, 'Spinning Armbar',            'SUBMISSION', 'Armbar rotacional desde cualquier posición haciendo una vuelta completa sobre el brazo del oponente.',                                                                                     'https://www.youtube.com/watch?v=xQ_pN7KZkqk', 'PURPLE', 'BOTH', 9,  40, 'PUBLIC', 'ARMBARS',         NOW(), NOW(), 0),
(120, 1, 'Shoulder Lock',              'SUBMISSION', 'Llave de hombro sin figura de 4, sólo usando el peso y la torsión directa. Variante simple pero efectiva.',                                                                               'https://www.youtube.com/watch?v=vJ5EOWy5C2o', 'WHITE',  'BOTH', 9,  40, 'PUBLIC', 'SHOULDER_LOCKS',  NOW(), NOW(), 0),
(121, 1, 'Kimura from Guard',          'SUBMISSION', 'Kimura atacada desde guardia cerrada o mariposa. El grip de kimura desde abajo también es herramienta de control.',                                                                       'https://www.youtube.com/watch?v=vCxEHjWFMls', 'WHITE',  'BOTH', 19, 40, 'PUBLIC', 'SHOULDER_LOCKS',  NOW(), NOW(), 0),
(122, 1, 'Kimura from Back',           'SUBMISSION', 'Kimura atacada desde back mount cuando los ganchos están en su lugar. Alta tasa de finalización.',                                                                                         'https://www.youtube.com/watch?v=vCxEHjWFMls', 'BLUE',   'BOTH', 8,  40, 'PUBLIC', 'SHOULDER_LOCKS',  NOW(), NOW(), 0),
(123, 1, 'Hammerlock',                 'SUBMISSION', 'Llave de hombro empujando la mano hacia la espalda (chicken wing). Desde back mount o crucifix.',                                                                                         'https://www.youtube.com/watch?v=vCxEHjWFMls', 'PURPLE', 'BOTH', 8,  40, 'PUBLIC', 'SHOULDER_LOCKS',  NOW(), NOW(), 0),
(124, 1, 'Ankle Lock from 50/50',      'SUBMISSION', 'Llave de tobillo desde posición 50/50. Atacar mientras el oponente también ataca crea urgencia táctica.',                                                                                 'https://www.youtube.com/watch?v=Aa8-FqNxXGk', 'BLUE',   'BOTH', 16, 40, 'PUBLIC', 'LEG_ENTANGLEMENT',NOW(), NOW(), 0),
(125, 1, 'Heel Hook from Saddle',      'SUBMISSION', 'Inside heel hook desde la posición saddle/honey hole (single leg X o ashi garami). El sistema de leg locks más eficiente del grappling moderno. IBJJF No-Gi: legal desde brown belt.',    'https://www.youtube.com/watch?v=2VRnDjJLCQQ', 'BROWN',  'NOGI', 53, 40, 'PUBLIC', 'LEG_ENTANGLEMENT',NOW(), NOW(), 0),
(126, 1, 'Outside Heel Hook 50/50',    'SUBMISSION', 'Outside heel hook desde la posición 50/50. Requiere completar el reaping de la pierna. IBJJF No-Gi: legal desde brown belt en la posición 50/50 con control adecuado.',                   'https://www.youtube.com/watch?v=Xhh0GGAEGmo', 'BROWN',  'NOGI', 16, 40, 'PUBLIC', 'LEG_ENTANGLEMENT',NOW(), NOW(), 0),
(127, 1, 'Heel Hook from Double Outside','SUBMISSION','Heel hook desde doble ashi exterior (outside ashi garami). Alto control de la pierna, ataque al ligamento externo. IBJJF No-Gi: legal desde brown belt. Sistema avanzado de leg entanglement.','https://www.youtube.com/watch?v=Xhh0GGAEGmo', 'BROWN', 'NOGI', 54, 40, 'PUBLIC', 'LEG_ENTANGLEMENT',NOW(), NOW(), 0),
(128, 1, 'Compression Lock',           'SUBMISSION', 'Compresión de articulación desde posición de control. Variante de shoulder lock. IBJJF: sin restricción específica, se aplica criterio de técnica avanzada desde purple belt.',           'https://www.youtube.com/watch?v=YVfHVbGX5OA', 'PURPLE', 'BOTH', 15, 40, 'PUBLIC', 'SHOULDER_LOCKS',  NOW(), NOW(), 0),
(129, 1, 'Hip Lock',                   'SUBMISSION', 'Llave de cadera torciendo la articulación de la cadera. Desde top side control o mount. Alta exigencia técnica.',                                                                         'https://www.youtube.com/watch?v=2VRnDjJLCQQ', 'BROWN',  'BOTH', 9,  40, 'PUBLIC', 'SHOULDER_LOCKS',  NOW(), NOW(), 0),
(130, 1, 'Toehold from Half Guard',    'SUBMISSION', 'Toe hold atacado desde half guard cuando el oponente intenta pasar. Sorpresivo y de alta efectividad.',                                                                                   'https://www.youtube.com/watch?v=RMdvLhAzuAU', 'PURPLE', 'BOTH', 20, 40, 'PUBLIC', 'HALF_GUARD',      NOW(), NOW(), 0),
(131, 1, 'Kneebar from Top',           'SUBMISSION', 'Kneebar desde posición top cuando el oponente abre las piernas para escapar. Rotación sobre la pierna y extensión de caderas para la sumisión. IBJJF: legal desde purple belt.',          'https://www.youtube.com/watch?v=xGRwB_JgNFs', 'PURPLE', 'BOTH', 46, 40, 'PUBLIC', 'LEG_ENTANGLEMENT',NOW(), NOW(), 0),
(132, 1, 'Neck Crank',                 'SUBMISSION', 'Manipulación cervical forzando la flexión o rotación del cuello. Técnica avanzada, ilegal en muchas competiciones gi.',                                                                   'https://www.youtube.com/watch?v=QvRmTGSGMoE', 'BROWN',  'NOGI', 55, 40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(133, 1, 'Truck Roll Choke',           'SUBMISSION', 'Estrangulación rodando desde la posición truck de 10th Planet. Crotch control más RNC.',                                                                                                  'https://www.youtube.com/watch?v=QvRmTGSGMoE', 'BROWN',  'NOGI', 47, 40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(134, 1, 'Darce from Turtle',          'SUBMISSION', 'D''Arce choke desde turtle top: insertar el brazo bajo el cuello mientras el oponente se defiende en tortuga.',                                                                           'https://www.youtube.com/watch?v=8mGJh6sTgN8', 'BLUE',   'NOGI', 13, 40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(135, 1, 'Buggy Choke',                'SUBMISSION', 'Triángulo con el brazo propio desde bottom side control. Contraintuitivo: sin moverse, atrapar el propio brazo.',                                                                         'https://www.youtube.com/watch?v=K8oMSsPJnGk', 'BROWN',  'BOTH', 35, 40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(136, 1, 'Shoulder Choke',             'SUBMISSION', 'Estrangulación usando el hombro propio empujando contra el cuello del oponente. No-gi. Desde side control pesado.',                                                                       'https://www.youtube.com/watch?v=rlV8UqBiMaw', 'PURPLE', 'NOGI', 9,  40, 'PUBLIC', 'CHOKES',          NOW(), NOW(), 0),
(137, 1, 'Inverted Armbar',            'SUBMISSION', 'Armbar invertido desde guardia o posición invertida atacando el codo en dirección opuesta al armbar estándar.',                                                                            'https://www.youtube.com/watch?v=xQ_pN7KZkqk', 'PURPLE', 'BOTH', 63, 40, 'PUBLIC', 'ARMBARS',         NOW(), NOW(), 0),
(138, 1, 'Overhead Sweep',             'TAKEDOWN',   'Barrido por encima de la cabeza desde guardia cerrada. El oponente cargar su peso hacia adelante y se lanza por encima.',                                                                  'https://www.youtube.com/watch?v=LowKXx1vI4E', 'WHITE',  'BOTH', 19, 9,  'PUBLIC', 'BUTTERFLY_GUARD', NOW(), NOW(), 0),
