(156, 1, 'Dogfight Back Take',         'TAKEDOWN',   'Desde dogfight: cuando ambos compiten underhooks, tirar el brazo lejano para tomar la espalda.',                                                                                         'https://www.youtube.com/watch?v=Hs9DqZr8JrA', 'BLUE',   'BOTH', 51, 8,  'PUBLIC', 'BACK_TAKES',      NOW(), NOW(), 0),
(157, 1, 'Spider Tomo Sweep',          'TAKEDOWN',   'Barrido de sacrificio desde spider guard: jalar bíceps y empujar con pies para proyectar hacia atrás al oponente.',                                                                      'https://www.youtube.com/watch?v=b5hFJ7_FPL0', 'BLUE',   'GI',   27, 6,  'PUBLIC', 'OPEN_GUARD',      NOW(), NOW(), 0),
(158, 1, 'Knee Cut to Mount',          'PASS',       'Variante del knee slice que termina directamente en mount aprovechando el momentum del corte de rodilla.',                                                                                'https://www.youtube.com/watch?v=m6pz-aFyAnU', 'BLUE',   'BOTH', 20, 6,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(159, 1, 'Pressure Pass',              'PASS',       'Pase de presión máxima usando el peso corporal para aplanar al oponente y lentamente pasar la guardia.',                                                                                  'https://www.youtube.com/watch?v=LlupBr_BKWU', 'BLUE',   'BOTH', 19, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(160, 1, 'Folding Pass',               'PASS',       'Doblar las piernas del oponente sobre su propio cuerpo para pasar. Stack y presión en mismo movimiento.',                                                                                 'https://www.youtube.com/watch?v=7N3EWb-4NXI', 'BLUE',   'BOTH', 19, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(161, 1, 'Headquarters Pass',          'PASS',       'Posición entre half guard y side control: una rodilla en el suelo, otra fuera. Controla antes de decidir la dirección del pase.',                                                         'https://www.youtube.com/watch?v=DtXbmQMPLrs', 'BLUE',   'BOTH', 20, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(162, 1, 'Roll Under Pass',            'PASS',       'Rodar bajo las piernas del oponente para aparecer al otro lado. Contra spider guard y guardias cerradas de pies altos.',                                                                  'https://www.youtube.com/watch?v=IGFK_oWVmIA', 'PURPLE', 'GI',   27, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(163, 1, 'Stack Pass',                 'PASS',       'Apilar al oponente sobre sus propios hombros. Presión cervical. Se combina con double under para pasar.',                                                                                 'https://www.youtube.com/watch?v=7N3EWb-4NXI', 'WHITE',  'BOTH', 19, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(164, 1, 'Toreando 3/4 Pass',          'PASS',       'Torreando incompleto que deja una rodilla al suelo: posición de headquarters para controlar medio camino del pase.',                                                                      'https://www.youtube.com/watch?v=LlupBr_BKWU', 'BLUE',   'BOTH', 18, 20, 'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(165, 1, 'Reverse Half Pass',          'PASS',       'Pasar la media guardia del lado inverso: en lugar de cruzar, dar la vuelta por detrás del oponente.',                                                                                     'https://www.youtube.com/watch?v=IGFK_oWVmIA', 'PURPLE', 'BOTH', 20, 8,  'PUBLIC', 'HALF_GUARD',      NOW(), NOW(), 0),
(166, 1, 'Leg Drag to Back',           'PASS',       'Leg drag que convierte el pase en toma de espalda cuando el oponente gira para seguir el arrastre de pierna.',                                                                            'https://www.youtube.com/watch?v=fqFCEqnSJJg', 'BLUE',   'BOTH', 25, 8,  'PUBLIC', 'BACK_TAKES',      NOW(), NOW(), 0),
(167, 1, 'Forced Half Pass',           'PASS',       'Forzar al oponente a media guardia desde guardia cerrada y luego terminar el pase desde ahí. Flujo estructurado.',                                                                        'https://www.youtube.com/watch?v=LlupBr_BKWU', 'WHITE',  'BOTH', 19, 9,  'PUBLIC', 'HALF_GUARD',      NOW(), NOW(), 0),
(168, 1, 'Lasso Guard Pass',           'PASS',       'Pasar la lasso guard: liberar el brazo enroscado, controlar la cadera y pasar rápido antes de que recupere el control.',                                                                  'https://www.youtube.com/watch?v=RAQiYBz0FiQ', 'PURPLE', 'GI',   28, 9,  'PUBLIC', 'OPEN_GUARD',      NOW(), NOW(), 0),
(169, 1, 'Spider Guard Pass',          'PASS',       'Pasar la spider guard: bajar los pies de los bíceps, controlar las rodillas, torreando o knee cut.',                                                                                      'https://www.youtube.com/watch?v=b5hFJ7_FPL0', 'BLUE',   'GI',   27, 9,  'PUBLIC', 'OPEN_GUARD',      NOW(), NOW(), 0),
(170, 1, 'Hip Escape Pass Counter',    'PASS',       'Seguir el shrimp del oponente desde side control para avanzar a mount o norte-sur sin perder el control.',                                                                                'https://www.youtube.com/watch?v=m6pz-aFyAnU', 'BLUE',   'BOTH', 35, 6,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(171, 1, 'Knee Tap Pass',              'PASS',       'Mover la rodilla del oponente a un lado para abrir paso al lado contrario. Velocidad y timing críticos.',                                                                                 'https://www.youtube.com/watch?v=DtXbmQMPLrs', 'WHITE',  'BOTH', 18, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(172, 1, 'Drive Through Pass',         'PASS',       'Empujar a través del centro de la guardia con cadera baja. No-gi. Contra guardias abiertas ligeras.',                                                                                     'https://www.youtube.com/watch?v=LlupBr_BKWU', 'BLUE',   'NOGI', 24, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(173, 1, 'Cartwheel Pass',             'PASS',       'Pase acrobático voltereta lateral sobre las piernas del oponente. Gi y no-gi. Alta recompensa, requiere atletismo.',                                                                      'https://www.youtube.com/watch?v=_B9VxJlCjUQ', 'PURPLE', 'BOTH', 25, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(174, 1, 'Esgrima Pass',               'PASS',       'Pase de esgrima: un brazo controla la rodilla, el otro empuja la cadera, paso lateral rápido. Sin gi.',                                                                                   'https://www.youtube.com/watch?v=fqFCEqnSJJg', 'BLUE',   'NOGI', 18, 9,  'PUBLIC', 'GUARD_PASSES',    NOW(), NOW(), 0),
(175, 1, 'Half Guard Top Pass',        'PASS',       'Completar el pase desde half guard top usando underpinning: hundirse bajo el underhook y rodar a mount.',                                                                                 'https://www.youtube.com/watch?v=xGLDU3qLBr0', 'BLUE',   'BOTH', 20, 6,  'PUBLIC', 'HALF_GUARD',      NOW(), NOW(), 0),
(176, 1, 'Fireman Carry',              'TAKEDOWN',   'Proyección de bombero: control del brazo + pierna, volteo frontal. Gi y no-gi. Alta efectividad desde clinch.',                                                                           'https://www.youtube.com/watch?v=KRi-Fh7FiME', 'BLUE',   'BOTH', 42, 9,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(177, 1, 'Suplex',                     'TAKEDOWN',   'Proyección hacia atrás elevando al oponente. Gi y no-gi. Muy espectacular pero requiere fuerza y timing.',                                                                                'https://www.youtube.com/watch?v=KRi-Fh7FiME', 'BLUE',   'BOTH', 44, 9,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(178, 1, 'Inside Trip',                'TAKEDOWN',   'Viaje de pie interior desde clinch: pierna barre la parte interna de la rodilla del oponente.',                                                                                           'https://www.youtube.com/watch?v=oIeadGdJMiY', 'WHITE',  'BOTH', 2,  9,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(179, 1, 'Outside Trip',               'TAKEDOWN',   'Viaje de pie exterior: pierna barre la parte externa de la rodilla. Judo (Osoto-gari). Muy común en BJJ.',                                                                               'https://www.youtube.com/watch?v=oIeadGdJMiY', 'WHITE',  'BOTH', 2,  9,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(180, 1, 'High Crotch',                'TAKEDOWN',   'Variante del single leg con control más alto en la ingle. Transición a single leg takedown o double leg.',                                                                                'https://www.youtube.com/watch?v=eJv7MNcH6X0', 'WHITE',  'BOTH', 3,  9,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(181, 1, 'Knee Pick',                  'TAKEDOWN',   'Agarre de la rodilla del oponente jalándola hacia arriba mientras se empuja el cuerpo. Bajo riesgo.',                                                                                     'https://www.youtube.com/watch?v=aSFJhfkNqYA', 'WHITE',  'BOTH', 2,  9,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(182, 1, 'Duck Under',                 'TAKEDOWN',   'Duckar bajo el brazo del oponente para tomar la espalda o ejecutar derribo. Desde collar tie o underhook.',                                                                               'https://www.youtube.com/watch?v=eJv7MNcH6X0', 'BLUE',   'BOTH', 43, 8,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(183, 1, 'Blast Double Leg',           'TAKEDOWN',   'Double leg explosivo sin pasos intermedios, directo desde neutral. Alta velocidad de entrada.',                                                                                           'https://www.youtube.com/watch?v=oIeadGdJMiY', 'BLUE',   'NOGI', 1,  9,  'PUBLIC', 'OTHER',           NOW(), NOW(), 0),
(184, 1, 'Uchi Mata',                  'TAKEDOWN',   'Proyección de judo con el muslo interior. Alta efectividad en competición de gi. Requiere buen kuzushi.',                                                                                 'https://www.youtube.com/watch?v=haBSH7XWJME', 'BLUE',   'GI',   2,  9,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(185, 1, 'Seoi Otoshi',                'TAKEDOWN',   'Caída de espalda hacia adelante cargando al oponente sobre el hombro sin la rotación completa del Seoi Nage.',                                                                            'https://www.youtube.com/watch?v=7fjjJgqMDvY', 'BLUE',   'GI',   2,  9,  'PUBLIC', 'TAKEDOWNS',       NOW(), NOW(), 0),
(186, 1, 'Shrimp to Guard',            'ESCAPE',     'Hip escape (gambas) desde bottom side control para crear espacio e insertar la rodilla y recuperar guardia.',                                                                             'https://www.youtube.com/watch?v=S9pqjRWBNL0', 'WHITE',  'BOTH', 35, 19, 'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(187, 1, 'Granby Roll',                'ESCAPE',     'Rodillo de hombro invertido para escapar de pressure passing o turtle. Recuperar guardia rodando por encima.',                                                                            'https://www.youtube.com/watch?v=5ALqUk9uefk', 'BLUE',   'BOTH', 38, 63, 'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(188, 1, 'Mount Escape to Deep Half',  'ESCAPE',     'Desde bottom mount, hundir la cadera y rodarse al lado para entrar a deep half guard en lugar de half guard estándar.',                                                                   'https://www.youtube.com/watch?v=OZ8sfB4SLuE', 'BLUE',   'BOTH', 36, 22, 'PUBLIC', 'HALF_GUARD',      NOW(), NOW(), 0),
(189, 1, 'Leg Pummeling',              'ESCAPE',     'Pelea de piernas para reconfigurar el leg entanglement: reposicionar la pierna atrapada para salir o mejorar.',                                                                           'https://www.youtube.com/watch?v=fqFCEqnSJJg', 'PURPLE', 'NOGI', 15, 18, 'PUBLIC', 'OTHER',           NOW(), NOW(), 0),
(190, 1, 'Standing Up from Bottom',    'ESCAPE',     'Levantarse técnicamente desde bottom guard: dos manos al suelo, pie libre adelante, explosión hacia arriba.',                                                                             'https://www.youtube.com/watch?v=dqFpT1XCLIM', 'WHITE',  'BOTH', 19, 1,  'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(191, 1, 'Scarf Hold Escape',          'ESCAPE',     'Escape de kesa gatame: puente y rodillo o insertar la rodilla para girar y recuperar guardia.',                                                                                           'https://www.youtube.com/watch?v=S9pqjRWBNL0', 'WHITE',  'BOTH', 12, 20, 'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(192, 1, 'Back Defense Hip Escape',    'ESCAPE',     'Defensa de espalda usando hip escape lateral: deslizarse por debajo de un gancho para liberar la posición.',                                                                              'https://www.youtube.com/watch?v=CRllVj7jriY', 'BLUE',   'BOTH', 37, 20, 'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(193, 1, 'Turtle Granby',              'ESCAPE',     'Desde turtle, rodar con el hombro en arco para reconfigurar y recuperar guardia o llegar a posición neutral.',                                                                            'https://www.youtube.com/watch?v=5ALqUk9uefk', 'BLUE',   'BOTH', 38, 20, 'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(194, 1, 'Choke Defense',              'ESCAPE',     'Defensa de estrangulaciones: tucking the chin, gripper''s elbows, crear espacio para el cuello y escapar.',                                                                               'https://www.youtube.com/watch?v=CRllVj7jriY', 'WHITE',  'BOTH', 37, 9,  'PUBLIC', 'ESCAPES',         NOW(), NOW(), 0),
(195, 1, 'North-South Back Roll',      'ESCAPE',     'Desde north-south invertido, rodar hacia atrás sobre los hombros para recuperar guardia dándole la vuelta.',                                                                              'https://www.youtube.com/watch?v=S9pqjRWBNL0', 'BLUE',   'BOTH', 35, 19, 'PUBLIC', 'BACK_TAKES',      NOW(), NOW(), 0),
(196, 1, 'Side Control to Crucifix',   'TRANSITION', 'Desde side control cuando el oponente inserta un brazo para escapar, atrapar ese brazo con las piernas.',                                                                                'https://www.youtube.com/watch?v=5ALqUk9uefk', 'BLUE',   'BOTH', 9,  14, 'PUBLIC', 'OTHER',           NOW(), NOW(), 0),
(197, 1, 'Knee On Belly to Armbar',    'TRANSITION', 'Desde knee on belly: cuando el oponente empuja la rodilla, rotar hacia el armbar aprovechando el brazo extendido.',                                                                      'https://www.youtube.com/watch?v=xQ_pN7KZkqk', 'BLUE',   'BOTH', 11, 40, 'PUBLIC', 'ARMBARS',         NOW(), NOW(), 0),
(198, 1, 'Turtle to Crucifix',         'TRANSITION', 'Desde turtle top: insertar la pierna dentro de las piernas del oponente para entrar a la posición crucifix.',                                                                            'https://www.youtube.com/watch?v=5ALqUk9uefk', 'PURPLE', 'BOTH', 13, 14, 'PUBLIC', 'BACK_TAKES',      NOW(), NOW(), 0),
(199, 1, 'Guard to Turtle',            'TRANSITION', 'Rodar de guardia a turtle cuando el oponente pasa agresivamente. Defensive reset.',                                                                                                       'https://www.youtube.com/watch?v=5ALqUk9uefk', 'WHITE',  'BOTH', 19, 38, 'PUBLIC', 'CLOSED_GUARD',    NOW(), NOW(), 0),
(200, 1, 'DLR to Berimbolo',           'TRANSITION', 'Entrar al berimbolo desde DLR cuando el oponente intenta pasar. Inversión completa bajo el oponente.',                                                                                   'https://www.youtube.com/watch?v=9aUCnvLCMg0', 'PURPLE', 'GI',   25, 8,  'PUBLIC', 'DLR_GUARD',       NOW(), NOW(), 0),
(201, 1, 'Mount to Triangle',          'TRANSITION', 'Configurar el triángulo desde mount cuando el oponente extiende los brazos para escapar el mount.',                                                                                      'https://www.youtube.com/watch?v=K8oMSsPJnGk', 'BLUE',   'BOTH', 6,  19, 'PUBLIC', 'TRIANGLES',       NOW(), NOW(), 0),
(202, 1, 'Side Control to Leg Lock',   'TRANSITION', 'Desde side control top: pivotar hacia las piernas del oponente para entrar a ashi garami o saddle.',                                                                                     'https://www.youtube.com/watch?v=JT0GQ9YTCGU', 'PURPLE', 'NOGI', 9,  53, 'PUBLIC', 'LEG_ENTANGLEMENT',NOW(), NOW(), 0),
(203, 1, 'Closed Guard to Spider',     'TRANSITION', 'Abrir la guardia y reconfigurar los pies a bíceps del oponente para pasar de closed a spider guard.',                                                                                    'https://www.youtube.com/watch?v=b5hFJ7_FPL0', 'BLUE',   'GI',   19, 27, 'PUBLIC', 'CLOSED_GUARD',    NOW(), NOW(), 0),
(204, 1, 'Closed Guard to DLR',        'TRANSITION', 'Transición de guardia cerrada a De La Riva cuando el oponente se levanta a base neutral.',                                                                                               'https://www.youtube.com/watch?v=9aUCnvLCMg0', 'BLUE',   'GI',   19, 25, 'PUBLIC', 'DLR_GUARD',       NOW(), NOW(), 0),
(205, 1, 'Half Guard to Z-Guard',      'TRANSITION', 'Desde half guard insertar la rodilla como escudo para crear la posición de Z-guard con más control de distancia.',                                                                       'https://www.youtube.com/watch?v=xGLDU3qLBr0', 'WHITE',  'BOTH', 20, 21, 'PUBLIC', 'HALF_GUARD',      NOW(), NOW(), 0),
(206, 1, 'SLX to Saddle',              'TRANSITION', 'Reconfigurar las piernas de single leg X a saddle/honey hole para mejorar el ángulo del heel hook.',                                                                                     'https://www.youtube.com/watch?v=JT0GQ9YTCGU', 'PURPLE', 'NOGI', 30, 53, 'PUBLIC', 'LEG_ENTANGLEMENT',NOW(), NOW(), 0),
(207, 1, 'Back to Mount',              'TRANSITION', 'Desde back mount: cuando se pierde un gancho, pivotar hacia adelante para llegar a mount alto.',                                                                                         'https://www.youtube.com/watch?v=CRllVj7jriY', 'WHITE',  'BOTH', 8,  7,  'PUBLIC', 'BACK_TAKES',      NOW(), NOW(), 0),
(208, 1, 'Turtle to Leg Lock Entry',   'TRANSITION', 'Desde turtle top: pasar la pierna por encima para entrar directamente a ashi garami o saddle.',                                                                                          'https://www.youtube.com/watch?v=JT0GQ9YTCGU', 'PURPLE', 'NOGI', 13, 53, 'PUBLIC', 'LEG_ENTANGLEMENT',NOW(), NOW(), 0),
(209, 1, 'Butterfly to X-Guard',       'TRANSITION', 'Desde butterfly guard: reconfigurar los ganchos para llegar a X-guard cuando el oponente se levanta.',                                                                                   'https://www.youtube.com/watch?v=QzIBt7FIqJQ', 'BLUE',   'BOTH', 24, 29, 'PUBLIC', 'BUTTERFLY_GUARD', NOW(), NOW(), 0)
INSERT INTO exercise (id, owner_id, name, description, category, equipment, youtube_url, visibility, created_at, updated_at, version) OVERRIDING SYSTEM VALUE VALUES
(1,  1, 'Push-Up',                           'Flexión de brazos estándar. Palmas ligeramente más anchas que los hombros, cuerpo recto, pecho casi tocando el suelo. Trabaja pectoral, tríceps y core.',                                          'STRENGTH',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=IODxDxX7oi4', 'PUBLIC', NOW(), NOW(), 0),
(2,  1, 'Diamond Push-Up',                   'Flexión con las manos formando un diamante bajo el pecho. Aisla el tríceps y la porción interna del pectoral. Esencial para mejorar finalizaciones de armbar.',                                    'STRENGTH',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=J0DnG1_S92I', 'PUBLIC', NOW(), NOW(), 0),
(3,  1, 'Wide Push-Up',                      'Flexión con manos muy abiertas. Mayor énfasis en pectoral externo. Mejora el framing y el control de distancia desde guardia.',                                                                    'STRENGTH',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=JScZgCrcJQU', 'PUBLIC', NOW(), NOW(), 0),
(4,  1, 'Archer Push-Up',                    'Flexión unilateral: un brazo extendido al lado mientras el otro dobla. Desarrolla fuerza asimétrica y propioception. Progresión hacia push-up con un brazo.',                                      'STRENGTH',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=MxVbNel13Ek', 'PUBLIC', NOW(), NOW(), 0),
(5,  1, 'Pike Push-Up',                      'Flexión en V invertida con las caderas elevadas. Carga el hombro como un press vertical. Preparación para el handstand push-up.',                                                                  'STRENGTH',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=fXgou2W10ok', 'PUBLIC', NOW(), NOW(), 0),
(6,  1, 'Bodyweight Squat',                  'Sentadilla con el peso corporal. Talones en el suelo, rodillas siguiendo la dirección de los pies, caderas por debajo de las rodillas. Base de toda la fuerza de piernas.',                        'STRENGTH',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=aclHkVaku9U', 'PUBLIC', NOW(), NOW(), 0),
(7,  1, 'Jump Squat',                        'Sentadilla pliométrica con salto explosivo al final del movimiento. Desarrolla potencia de piernas para derribos y barridos explosivos.',                                                          'STRENGTH',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=BRfxI2Es2lE', 'PUBLIC', NOW(), NOW(), 0),
(8,  1, 'Bulgarian Split Squat',             'Sentadilla búlgara: pie trasero elevado, pie delantero adelantado. Trabaja cuádriceps, glúteo y equilibrio unilateral. Sin material externo si se apoya en silla.',                               'STRENGTH',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=2C-uNgKwPLE', 'PUBLIC', NOW(), NOW(), 0),
(9,  1, 'Pistol Squat',                      'Sentadilla a una pierna. Máxima exigencia unilateral de cuádriceps, glúteo y equilibrio. Requiere meses de progresión. Excelente para prevención de lesiones de rodilla.',                        'STRENGTH',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=vq5-vdgJc0I', 'PUBLIC', NOW(), NOW(), 0),
(10, 1, 'Inverted Row (Table)',              'Remo invertido bajo una mesa o barra baja. Cuerpo recto, tirar del pecho hacia la superficie. Trabaja dorsales y bíceps sin material de gym.',                                                     'STRENGTH',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=OYUxXMGVuuU', 'PUBLIC', NOW(), NOW(), 0),
(11, 1, 'Plank',                             'Plancha isométrica en codos y puntas de pie. Mantener el cuerpo completamente recto sin caer las caderas. Activa toda la cadena anterior del tronco.',                                             'CORE',        'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=pSHjTRCQxIw', 'PUBLIC', NOW(), NOW(), 0),
(12, 1, 'Side Plank',                        'Plancha lateral: apoyo en un codo y el borde del pie. Activa oblicuos, cuadrado lumbar y glúteo medio. Imprescindible para la estabilidad lateral en guardia.',                                   'CORE',        'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=N_s9em1xTqU', 'PUBLIC', NOW(), NOW(), 0),
(13, 1, 'Hollow Body Hold',                  'Decúbito supino: piernas y hombros elevados, zona lumbar pegada al suelo. La posición base de la gimnasia y del core funcional. Clave para guardias activas.',                                     'CORE',        'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=LlDNef_Ztsc', 'PUBLIC', NOW(), NOW(), 0),
(14, 1, 'Dead Bug',                          'Decúbito supino: piernas y brazos opuestos se alargan simultáneamente sin perder el contacto lumbar. Mejora la coordinación y estabilidad profunda del core.',                                     'CORE',        'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=4XLEnwUr1d8', 'PUBLIC', NOW(), NOW(), 0),
(15, 1, 'V-Up',                              'Desde decúbito supino, elevar piernas y tronco simultáneamente hacia el centro formando una V. Activa recto abdominal y flexores de cadera.',                                                      'CORE',        'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=iP2fjvG0g3w', 'PUBLIC', NOW(), NOW(), 0),
(16, 1, 'Leg Raise',                         'Desde decúbito supino, elevar las piernas juntas hasta 90° sin doblarlas. Trabaja la porción inferior del recto abdominal y los flexores de cadera.',                                              'CORE',        'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=2n4UqRIJyk4', 'PUBLIC', NOW(), NOW(), 0),
(17, 1, 'Mountain Climber',                  'Posición de push-up, llevar las rodillas alternadamente al pecho con rapidez. Combina core con cardio. Simula la explosividad del shrimp bajo presión.',                                          'CORE',        'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=cnyTQDSE884', 'PUBLIC', NOW(), NOW(), 0),
(18, 1, 'Ab Wheel Rollout (towel variation)','Rollout con una toalla sobre suelo liso: manos en la toalla, rodar hacia adelante y volver. Trabaja el core anterior con enorme rango de movimiento.',                                             'CORE',        'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=A3uK5TPzHq8', 'PUBLIC', NOW(), NOW(), 0),
(19, 1, 'Russian Twist',                     'Sentado en V, torcer el tronco de lado a lado. Sin peso externo ya trabaja los oblicuos. Simula el giro del torso en barridos y técnicas rotacionales.',                                           'CORE',        'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=wkD8rjkodUI', 'PUBLIC', NOW(), NOW(), 0),
(20, 1, 'Bear Crawl',                        'Cuadrupedia con rodillas a 5 cm del suelo. Avanzar, retroceder o lateral. Activa core, hombros y cadera de forma integrada. Excelente para la coordinación de BJJ.',                               'CORE',        'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=LCVMqEmgglo', 'PUBLIC', NOW(), NOW(), 0),
(21, 1, 'Burpee',                            'Thrust al suelo, push-up, salto y palmada arriba. El ejercicio de acondicionamiento total más completo para BJJ. Simula la intensidad de los rounds.',                                             'CARDIO',      'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=qLBImHhCXSw', 'PUBLIC', NOW(), NOW(), 0),
(22, 1, 'Sprint',                            'Carrera a máxima velocidad en distancias cortas (20-50 m). Desarrolla el sistema de fosfágenos y la capacidad de explosiones repetidas en combate.',                                               'CARDIO',      'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=3Du0OiBJz0Y', 'PUBLIC', NOW(), NOW(), 0),
(23, 1, 'Shadow Grappling',                  'Practicar técnicas BJJ en el aire: shots, sprawls, barridos y transiciones sin oponente. Mejora la técnica, el ritmo y el acondicionamiento simultáneamente.',                                     'CARDIO',      'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=yLKTfEwVaFQ', 'PUBLIC', NOW(), NOW(), 0),
(24, 1, 'Hip Escape Drill',                  'Ejercicio de gambas continuo a lo largo del tatami: bridge + shrimp repetitivo. Acondicionamiento específico del movimiento más importante de la defensa.',                                        'CARDIO',      'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=D6toRF1vM7s', 'PUBLIC', NOW(), NOW(), 0),
(25, 1, 'Technical Stand Drill',             'Levantarse técnicamente de guardia repetidas veces: mano trasera al suelo, pie libre adelante, subir a postura. Acondicionamiento y técnica combinados.',                                          'CARDIO',      'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=yC_sSqO4Vx0', 'PUBLIC', NOW(), NOW(), 0),
(26, 1, 'High Knees',                        'Carrera en el sitio con rodillas elevadas al pecho. Alta frecuencia de zancada. Prepara el sistema cardiovascular y los flexores de cadera.',                                                      'CARDIO',      'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=QPfOZ0e30xg', 'PUBLIC', NOW(), NOW(), 0),
(27, 1, 'Box Jump (floor level)',            'Salto desde posición de cuclillas a posición de pie completamente extendida. Sin caja. Desarrolla la potencia del tren inferior y la reactividad.',                                                'CARDIO',      'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=HJZh-12p6vg', 'PUBLIC', NOW(), NOW(), 0),
(28, 1, 'Hip Circle',                        'Rotación completa de la cadera en círculos grandes, de pie. Calienta la articulación coxofemoral antes de entrenamiento o competición.',                                                           'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=Wh1Kg2iqBiw', 'PUBLIC', NOW(), NOW(), 0),
(29, 1, 'Spiderman Stretch',                 'Zancada profunda con la mano en el suelo al nivel del pie adelantado, cadera baja. Movilidad de cadera y flexibilidad de psoas. Esencial para guardas abiertas.',                                 'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=FkplpLaXBAE', 'PUBLIC', NOW(), NOW(), 0),
(30, 1, 'World Greatest Stretch',            'Combinación en un movimiento: lunge + rotación de tronco + extensión de cadera. Movilidad global de cadena posterior, torácica y cadera.',                                                        'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=-CiWQ2IvY34', 'PUBLIC', NOW(), NOW(), 0),
(31, 1, 'Neck Bridge',                       'Puente sobre la cabeza y los talones. Fortalece y moviliza la columna cervical. Fundamental para la defensa de estrangulaciones y el wrestling.',                                                  'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=vMMbHjoCgoE', 'PUBLIC', NOW(), NOW(), 0),
(32, 1, 'Shoulder Dislocate',                'Rotación completa de hombros con un palo o toalla: pasar de adelante a atrás con los brazos extendidos. Movilidad de hombro para guardia y control de espalda.',                                  'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=vP8YmmRMz6I', 'PUBLIC', NOW(), NOW(), 0),
(33, 1, 'Pull-Up',                           'Dominada con agarre prono en cualquier barra de puerta o rama. El ejercicio de tren superior más importante para el BJJ. Trabaja dorsales, bíceps y core.',                                        'STRENGTH',    'HOME',         'https://www.youtube.com/watch?v=eGo4IYlbE5g', 'PUBLIC', NOW(), NOW(), 0),
(34, 1, 'Chin-Up',                           'Dominada con agarre supino (manos hacia el cuerpo). Mayor activación del bíceps. Complementa el pull-up para una espalda equilibrada.',                                                            'STRENGTH',    'HOME',         'https://www.youtube.com/watch?v=e1YSApl-QcM', 'PUBLIC', NOW(), NOW(), 0),
(35, 1, 'Resistance Band Row',               'Remo con banda elástica fijada en una puerta. Simula el pulling de clinch y control de espalda. Progresa aumentando la resistencia de la banda.',                                                 'STRENGTH',    'HOME',         'https://www.youtube.com/watch?v=LSkyinhmA8k', 'PUBLIC', NOW(), NOW(), 0),
(36, 1, 'Resistance Band Pull-Apart',        'Sosteniendo la banda a altura de pecho, separar los brazos hasta tocar el pecho. Trabaja los retractores escapulares y el manguito rotador posterior.',                                           'STRENGTH',    'HOME',         'https://www.youtube.com/watch?v=osRimvxXlKQ', 'PUBLIC', NOW(), NOW(), 0),
(37, 1, 'Resistance Band Press',             'Press de pecho con banda fijada detrás. Trabaja el empuje horizontal. Usar en superserie con remo para equilibrio de empuje/tracción.',                                                            'STRENGTH',    'HOME',         'https://www.youtube.com/watch?v=Rn-hf5iauTc', 'PUBLIC', NOW(), NOW(), 0),
(38, 1, 'Glute Bridge',                      'Decúbito supino, rodillas dobladas, empujar las caderas hacia arriba apretando glúteos. Activa glúteos y cadena posterior. Previene lesiones de rodilla y cadera.',                               'STRENGTH',    'HOME',         'https://www.youtube.com/watch?v=X_IGw8U_e38', 'PUBLIC', NOW(), NOW(), 0),
(39, 1, 'Single Leg Glute Bridge',           'Puente de glúteo a una pierna. Mayor demanda unilateral. Corrige desequilibrios entre piernas y fortalece el glúteo para los derribos.',                                                          'STRENGTH',    'HOME',         'https://www.youtube.com/watch?v=sVfp4LN9niA', 'PUBLIC', NOW(), NOW(), 0),
(40, 1, 'Hip Thrust with Chair',             'Hombros apoyados en una silla, caderas elevándose desde el suelo con potencia. Máxima activación del glúteo mayor. Fundamental para la explosividad de cadera.',                                  'STRENGTH',    'HOME',         'https://www.youtube.com/watch?v=cj1hnHOJdNI', 'PUBLIC', NOW(), NOW(), 0),
(41, 1, 'Step-Up',                           'Subir y bajar un escalón o silla de forma controlada. Cuádriceps, isquios y glúteo unilateral. Trabaja el control excéntrico de la rodilla.',                                                     'STRENGTH',    'HOME',         'https://www.youtube.com/watch?v=wfhXnLILqdk', 'PUBLIC', NOW(), NOW(), 0),
(42, 1, 'Towel Row',                         'Remo usando una toalla alrededor de una puerta o poste. Simula el grip de gi. Trabaja la tracción y el agarre simultáneamente.',                                                                   'STRENGTH',    'HOME',         'https://www.youtube.com/watch?v=nZ1XyPqX-E4', 'PUBLIC', NOW(), NOW(), 0),
(43, 1, 'Jump Rope',                         'Comba de saltar. Uno de los mejores acondicionadores cardiovasculares. Mejora el ritmo, la coordinación y la resistencia aeróbica en sesiones de 10-20 min.',                                     'CARDIO',      'HOME',         'https://www.youtube.com/watch?v=1BZM2Vre5oc', 'PUBLIC', NOW(), NOW(), 0),
(44, 1, 'Double Under',                      'Comba donde la cuerda pasa dos veces por cada salto. Alta intensidad, mejora la explosividad de piernas y la coordinación ritmica.',                                                               'CARDIO',      'HOME',         'https://www.youtube.com/watch?v=pQRnSYfliEc', 'PUBLIC', NOW(), NOW(), 0),
(45, 1, 'Resistance Band Sprint',            'Sprint estático con banda elástica fijada detrás de la cintura. Trabaja la mecánica de la zancada y la potencia de cadera bajo resistencia.',                                                     'CARDIO',      'HOME',         'https://www.youtube.com/watch?v=ImGqKnWOP2U', 'PUBLIC', NOW(), NOW(), 0),
(46, 1, 'Stair Climbing',                    'Subir escaleras repetidamente a paso rápido o corriendo. Excelente cardio de baja impacto sobre las rodillas comparado con correr. Fácil de integrar en casa.',                                   'CARDIO',      'HOME',         'https://www.youtube.com/watch?v=a3hWSX4D5hY', 'PUBLIC', NOW(), NOW(), 0),
(47, 1, 'Towel Drag Drill',                  'Arrastrar una toalla con ropa húmeda por el suelo simulando el peso de un oponente. Trabaja la cadena posterior y el sistema cardiovascular.',                                                     'CARDIO',      'HOME',         'https://www.youtube.com/watch?v=1LymhTIa2mY', 'PUBLIC', NOW(), NOW(), 0),
(48, 1, 'Resistance Band Sprawl Drill',      'Con banda en caderas: shot a doble pierna y sprawl de vuelta de forma repetida. Simula la explosividad y el acondicionamiento del wrestling.',                                                    'CARDIO',      'HOME',         NULL,                                          'PUBLIC', NOW(), NOW(), 0),
(49, 1, 'Lateral Shuffle',                   'Desplazamientos laterales rápidos en posición de defensa. Mejora el footwork y la agilidad lateral. Fundamental para el movimiento de pie en BJJ.',                                               'CARDIO',      'HOME',         'https://www.youtube.com/watch?v=O9zzo7oiyK4', 'PUBLIC', NOW(), NOW(), 0),
(50, 1, 'Agility Ladder Drill',              'Ejercicios de pies en escalera de agilidad en el suelo. Múltiples patrones. Mejora la coordinación, el ritmo y la agilidad del footwork de lucha de pie.',                                        'CARDIO',      'HOME',         'https://www.youtube.com/watch?v=66oUAhI0nQQ', 'PUBLIC', NOW(), NOW(), 0),
(51, 1, 'Ab Wheel Rollout',                  'Con rueda abdominal desde rodillas: extender el cuerpo hacia adelante manteniendo la neutralidad lumbar y volver. El ejercicio de core más exigente.',                                             'CORE',        'HOME',         'https://www.youtube.com/watch?v=A3uK5TPzHq8', 'PUBLIC', NOW(), NOW(), 0),
(52, 1, 'Resistance Band Woodchop',          'Rotación diagonal del tronco con banda: desde cadera baja a hombro alto. Trabaja la cadena de rotación. Simula el movimiento de barridos y volteos.',                                              'CORE',        'HOME',         'https://www.youtube.com/watch?v=53Dgt1HiXHo', 'PUBLIC', NOW(), NOW(), 0),
(53, 1, 'Pallof Press',                      'Press isométrico anti-rotación con banda: resistir la rotación mientras se extienden los brazos. Entrena el core para estabilizar bajo carga rotacional.',                                        'CORE',        'HOME',         'https://www.youtube.com/watch?v=5aZ0IhJS8O8', 'PUBLIC', NOW(), NOW(), 0),
(54, 1, 'Dragon Flag',                       'Desde un banco o escalón: todo el cuerpo sube y baja rígido desde los hombros. Uno de los ejercicios de core más difíciles. Recto abdominal total.',                                              'CORE',        'HOME',         'https://www.youtube.com/watch?v=kICxJien7xM', 'PUBLIC', NOW(), NOW(), 0),
(55, 1, 'Yoga Hip Opener',                   'Secuencia de aperturas de cadera: pigeon pose, figura 4, lagartija profunda. 10-15 min diarios transforman la flexibilidad de cadera para la guardia.',                                            'FLEXIBILITY', 'HOME',         'https://www.youtube.com/watch?v=GffXQl3zvUI', 'PUBLIC', NOW(), NOW(), 0),
(56, 1, 'Thoracic Spine Rotation',           'Desde posición de cuadrupedia o de lado, rotar la columna torácica abriendo el pecho. Mejora el giro del tronco para barridos y control de espalda.',                                             'MOBILITY',    'HOME',         'https://www.youtube.com/watch?v=EHZJns1bXPM', 'PUBLIC', NOW(), NOW(), 0),
(57, 1, 'Couch Stretch',                     'Estiramiento de psoas con el pie trasero contra la pared o silla. Alivia la tensión de cadera de quienes pasan muchas horas sentados. Esencial pre-entrenamiento.',                               'FLEXIBILITY', 'HOME',         'https://www.youtube.com/watch?v=Fg-lwNBzVV8', 'PUBLIC', NOW(), NOW(), 0),
(58, 1, 'Foam Roller Thoracic',              'Extensión de columna torácica sobre rodillo o toalla enrollada. Contrarresta la flexión constante del BJJ. Mejora la postura y el rango de extensión.',                                            'MOBILITY',    'HOME',         'https://www.youtube.com/watch?v=SQF-0s1CckA', 'PUBLIC', NOW(), NOW(), 0),
(59, 1, 'Wall Hip Flexor Stretch',           'Estiramiento de hip flexor contra la pared: rodilla trasera en el suelo, pelvis en anteversión, empujar la cadera hacia adelante y abajo.',                                                       'FLEXIBILITY', 'HOME',         'https://www.youtube.com/watch?v=NVzs5gy11wQ', 'PUBLIC', NOW(), NOW(), 0),
(60, 1, 'Banded Shoulder Distraction',       'Banda fijada en alto, meter el brazo y dejar que la tracción separe la cabeza humeral del acromion. Recuperación y movilidad de hombro post-entrenamiento.',                                      'MOBILITY',    'HOME',         'https://www.youtube.com/watch?v=36PcBOwzMZs', 'PUBLIC', NOW(), NOW(), 0),
(61, 1, 'Deadlift',                          'Peso muerto convencional. El ejercicio de fuerza total más transferible al BJJ. Trabaja isquiotibiales, glúteo, espalda baja y grip. Base de todo programa de fuerza.',                           'STRENGTH',    'GYM',          'https://www.youtube.com/watch?v=XxWcirHIwVo', 'PUBLIC', NOW(), NOW(), 0),
(62, 1, 'Romanian Deadlift',                 'Peso muerto rumano: sin doblar las rodillas, bajar la barra por las piernas hasta sentir tensión en isquios. Trabaja la cadena posterior que potencia los derribos.',                             'STRENGTH',    'GYM',          'https://www.youtube.com/watch?v=_oyxCn2iSjU', 'PUBLIC', NOW(), NOW(), 0),
(63, 1, 'Barbell Back Squat',                'Sentadilla con barra en trapecio. El rey de los ejercicios de tren inferior. Trabaja cuádriceps, glúteo e isquios. Potencia directa en barridos y derribos.',                                     'STRENGTH',    'GYM',          'https://www.youtube.com/watch?v=rrJIyZGlK8c', 'PUBLIC', NOW(), NOW(), 0),
(64, 1, 'Front Squat',                       'Sentadilla frontal con barra en hombros. Mayor demanda en cuádriceps y core erector. Postura más vertical, transferible al shot de lucha libre.',                                                  'STRENGTH',    'GYM',          'https://www.youtube.com/watch?v=nmUof3vszxM', 'PUBLIC', NOW(), NOW(), 0),
(65, 1, 'Bench Press',                       'Press de banca con barra o mancuernas. Trabaja pectoral, deltoides anterior y tríceps. Fuerza de empuje horizontal relevante para el framing.',                                                   'STRENGTH',    'GYM',          'https://www.youtube.com/watch?v=gRVjAtPip0Y', 'PUBLIC', NOW(), NOW(), 0),
(66, 1, 'Barbell Row',                       'Remo con barra. Cuerpo paralelo al suelo, tirar la barra hacia el abdomen. El mejor ejercicio de tracción horizontal para el grip y la espalda del BJJ.',                                         'STRENGTH',    'GYM',          'https://www.youtube.com/watch?v=T3N-TO4reLQ', 'PUBLIC', NOW(), NOW(), 0),
(67, 1, 'Weighted Pull-Up',                  'Dominada lastrada con cinturón o chaleco. Progresión de la dominada estándar. Desarrolla la fuerza de latísimo necesaria para el clinch y el arm drag.',                                           'STRENGTH',    'GYM',          'https://www.youtube.com/watch?v=C0I0gb76yaA', 'PUBLIC', NOW(), NOW(), 0),
(68, 1, 'Overhead Press',                    'Press militar con barra o mancuernas de pie. Trabaja el deltoides medio y anterior, tríceps y core. Estabilidad de hombro para submissions y control.',                                           'STRENGTH',    'GYM',          'https://www.youtube.com/watch?v=_RlRDWO2jfg', 'PUBLIC', NOW(), NOW(), 0),
(69, 1, 'Hex Bar Deadlift',                  'Peso muerto con barra hexagonal. Posición más vertical, mayor activación de cuádriceps. Menor carga en la espalda baja. Ideal para atletas de combate.',                                          'STRENGTH',    'GYM',          'https://www.youtube.com/watch?v=a7sQPZsmxvA', 'PUBLIC', NOW(), NOW(), 0),
(70, 1, 'Dumbbell Farmer Walk',              'Cargar mancuernas pesadas y caminar. El ejercicio de grip y core más funcional para BJJ. Trabaja la musculatura de soporte de forma isométrica bajo carga.',                                       'STRENGTH',    'GYM',          'https://www.youtube.com/watch?v=1uOs1hP3u4A', 'PUBLIC', NOW(), NOW(), 0)
INSERT INTO exercise (id, owner_id, name, description, category, equipment, youtube_url, visibility, created_at, updated_at, version) OVERRIDING SYSTEM VALUE VALUES
(71,  1, 'Power Clean',                    'Arrancada de potencia desde el suelo a los hombros. Desarrolla la potencia explosiva total. Muy relevante para la velocidad de entrada en derribos.',                                            'STRENGTH',    'GYM',          'https://www.youtube.com/watch?v=5vVSGITznQk', 'PUBLIC', NOW(), NOW(), 0),
(72,  1, 'Barbell Hip Thrust',             'Hip thrust con barra sobre cadera. Máxima activación del glúteo mayor. Potencia de cadera para barridos explosivos y escapes desde bottom mount.',                                              'STRENGTH',    'GYM',          'https://www.youtube.com/watch?v=pF17m_CXfL0', 'PUBLIC', NOW(), NOW(), 0),
(73,  1, 'Face Pull',                      'Remo en polea alta jalando hacia la cara. Trabaja deltoides posterior, trapecios medios y manguito rotador. Previene lesiones de hombro por desequilibrio.',                                    'STRENGTH',    'GYM',          'https://www.youtube.com/watch?v=ljgqer1ZpXg', 'PUBLIC', NOW(), NOW(), 0),
(74,  1, 'Lat Pulldown',                   'Jalón en polea alta. Simula el pull-up con posibilidad de ajustar el peso. Trabaja latísimo del dorso, bíceps y estabilizadores escapulares.',                                                  'STRENGTH',    'GYM',          'https://www.youtube.com/watch?v=hnSqbBk15tw', 'PUBLIC', NOW(), NOW(), 0),
(75,  1, 'Sled Push',                      'Empujar trineo cargado. Acondicionamiento de fuerza resistencia del tren inferior. Muy específico para el drive del double leg y el body lock pass.',                                           'STRENGTH',    'GYM',          'https://www.youtube.com/watch?v=9XRRXaUpnLk', 'PUBLIC', NOW(), NOW(), 0),
(76,  1, 'Rowing Machine',                 'Remo en ergómetro. Trabaja todo el cuerpo en un patrón de tracción. Alta demanda cardiovascular. Intervalos de 500 m para simular la intensidad de un round.',                                 'CARDIO',      'GYM',          'https://www.youtube.com/watch?v=ZN0J6qKCIrI', 'PUBLIC', NOW(), NOW(), 0),
(77,  1, 'Assault Bike',                   'Bicicleta de aire con manubrios de brazos. El acondicionador más brutal para BJJ. Intervalos Tabata en assault bike elevan la capacidad anaeróbica máxima.',                                    'CARDIO',      'GYM',          'https://www.youtube.com/watch?v=Sg3Id7Lu8XU', 'PUBLIC', NOW(), NOW(), 0),
(78,  1, 'Battle Rope',                    'Ondas con cuerdas pesadas. Simula el clinch pummeling y el barrido de brazos. Intervals de 20-30 s con descanso. Cardio de tren superior altamente específico.',                               'CARDIO',      'GYM',          'https://www.youtube.com/watch?v=pQb2xIGioyQ', 'PUBLIC', NOW(), NOW(), 0),
(79,  1, 'Ski Erg',                        'Máquina de remo de pie simulando esquí de fondo. Patrón de jalón bilateral muy específico para el arrastre de brazos en clinch. Alta demanda cardiovascular.',                                  'CARDIO',      'GYM',          NULL,                                          'PUBLIC', NOW(), NOW(), 0),
(80,  1, 'Treadmill Sprint',               'Sprints en cinta a velocidad máxima. Intervalos cortos (10-15 s) con recuperación. Desarrolla el sistema de fosfágenos para las explosiones de BJJ.',                                          'CARDIO',      'GYM',          'https://www.youtube.com/watch?v=W110XPDTo4Q', 'PUBLIC', NOW(), NOW(), 0),
(81,  1, 'Cable Woodchop',                 'Rotación diagonal con polea: desde cadera hacia hombro contrario. Trabaja oblicuos y la cadena de rotación. Específico para barridos y control desde guardia.',                                'CORE',        'GYM',          'https://www.youtube.com/watch?v=53Dgt1HiXHo', 'PUBLIC', NOW(), NOW(), 0),
(82,  1, 'Cable Anti-Rotation Press',      'Pallof press con polea: resistir la rotación mientras se extienden los brazos hacia afuera. Entrena el core para resistir las fuerzas rotacionales de BJJ.',                                   'CORE',        'GYM',          'https://www.youtube.com/watch?v=5aZ0IhJS8O8', 'PUBLIC', NOW(), NOW(), 0),
(83,  1, 'Landmine Rotation',              'Barra en landmine: sujetar la barra con brazos extendidos y rotar de cadera a cadera. Potencia rotatoria con carga. Muy específico para sweeps y throws.',                                     'CORE',        'GYM',          'https://www.youtube.com/watch?v=LCVMqEmgglo', 'PUBLIC', NOW(), NOW(), 0),
(84,  1, 'Hanging Leg Raise',              'Colgado de la barra, elevar las piernas juntas a 90° o hasta el pecho. El mejor ejercicio de core inferior y agarre simultáneo. Durísimo para el grip.',                                       'CORE',        'GYM',          'https://www.youtube.com/watch?v=2n4UqRIJyk4', 'PUBLIC', NOW(), NOW(), 0),
(85,  1, 'Weighted Plank',                 'Plancha estándar con peso encima de la espalda. Progresión de la plancha para mayor demanda isométrica. Trabaja toda la cadena anterior del tronco.',                                          'CORE',        'GYM',          'https://www.youtube.com/watch?v=H88Ip-MUWn0', 'PUBLIC', NOW(), NOW(), 0),
(86,  1, 'Band-Assisted Hip Flexor',       'Con banda fijada en rack: tracción de cadera hacia atrás en lunge position. Libera la tensión del psoas iliaco después de sesiones de BJJ intensas.',                                          'MOBILITY',    'GYM',          'https://www.youtube.com/watch?v=hSnqRdDSdd4', 'PUBLIC', NOW(), NOW(), 0),
(87,  1, 'Box Hip Flexion',                'Apoyado en un plyo box, llevar la rodilla al pecho con control. Trabaja el rango activo de flexión de cadera, clave para guardar las piernas en guardia.',                                     'MOBILITY',    'GYM',          'https://www.youtube.com/watch?v=w7LgagAdcaM', 'PUBLIC', NOW(), NOW(), 0),
(88,  1, 'Nordic Hamstring Curl',          'Arrodillado con pies fijos, bajar el tronco controlando con los isquios. El mejor ejercicio excéntrico para prevenir roturas de isquiotibiales.',                                              'STRENGTH',    'GYM',          'https://www.youtube.com/watch?v=_e9vFU9-tkc', 'PUBLIC', NOW(), NOW(), 0),
(89,  1, 'Cable External Rotation',        'Rotación externa de hombro en polea: codo a 90°, rotar hacia afuera. Fortalece el manguito rotador. Prevención de la lesión de hombro más común en BJJ.',                                     'MOBILITY',    'GYM',          'https://www.youtube.com/watch?v=fuWq7fg74dc', 'PUBLIC', NOW(), NOW(), 0),
(90,  1, 'Jefferson Curl',                 'Peso muerto con flexión vertebral progresiva e intencional. Fortalece la cadena posterior en longitud. Solo para practicantes avanzados con buena técnica base.',                              'FLEXIBILITY', 'GYM',          'https://www.youtube.com/watch?v=rJfehSZOZyU', 'PUBLIC', NOW(), NOW(), 0),
(91,  1, 'Kettlebell Swing',               'Balanceo de kettlebell con explosión de cadera. Trabaja la cadena posterior completa de forma balística. Directamente transferible al hip bump sweep y escapes.',                              'OTHER',       'GYM',          'https://www.youtube.com/watch?v=h-A7HiTNZ5c', 'PUBLIC', NOW(), NOW(), 0),
(92,  1, 'Turkish Get-Up',                 'Levantarse del suelo a de pie con kettlebell en alto. Integra estabilidad de hombro, movilidad de cadera y fuerza funcional total. Movimiento muy específico para BJJ.',                      'OTHER',       'GYM',          'https://www.youtube.com/watch?v=sgd8n917Zv0', 'PUBLIC', NOW(), NOW(), 0),
(93,  1, 'Grip Training (gi)',             'Ejercicios específicos de agarre: towel pull-ups, gi pull-ups, plate pinch, bucket de arroz. Desarrolla el grip indispensable para el juego de gi.',                                           'OTHER',       'GYM',          'https://www.youtube.com/watch?v=m-2XH7vm2Hk', 'PUBLIC', NOW(), NOW(), 0),
(94,  1, 'Medicine Ball Slam',             'Lanzar un balón medicinal con fuerza al suelo desde arriba de la cabeza. Desarrolla la potencia de tracción hacia abajo. Específico para guillotinas y mat returns.',                         'OTHER',       'GYM',          'https://www.youtube.com/watch?v=QxYhFwMd1Ks', 'PUBLIC', NOW(), NOW(), 0),
(95,  1, 'Rotational Medicine Ball Throw', 'Lanzar el balón medicinal contra la pared con rotación de cadera. Potencia rotatoria explícita. Transferible a todos los sweeps y proyecciones del BJJ.',                                     'OTHER',       'GYM',          'https://www.youtube.com/watch?v=DttZ5JU-b_U', 'PUBLIC', NOW(), NOW(), 0),
(96,  1, 'Shrimp (Camarón)',               'Movimiento de cadera fundamental del BJJ para recuperar guardia. Empuja con los pies y escapa la cadera lateralmente tumbado en el suelo.',                                                    'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=D0rTw8IfJDE', 'PUBLIC', NOW(), NOW(), 0),
(97,  1, 'Granby Roll',                    'Voltereta lateral sobre el hombro, esencial para escapar de posiciones de control como el turtle o la presión de side control.',                                                               'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=oiwLe-l4cvM', 'PUBLIC', NOW(), NOW(), 0),
(98,  1, 'Technical Stand-Up',             'Levantarse del suelo guardando distancia y base. Técnica fundamental del BJJ de pie para recuperarse sin exponer la espalda.',                                                                 'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=quMmk9Xs2HE', 'PUBLIC', NOW(), NOW(), 0),
(100, 1, 'Sit-Out',                        'Transición explosiva de cuatro apoyos a posición lateral. Esencial para escapar del control de wrestling y crear ángulos.',                                                                    'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=_kbBhyxV0RY', 'PUBLIC', NOW(), NOW(), 0),
(101, 1, 'Stand-Up in Base',               'Levantarse manteniendo base estable contra derribos. Trabaja el equilibrio y la coordinación en el paso de suelo a pie.',                                                                      'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=JzEaiLDwIwc', 'PUBLIC', NOW(), NOW(), 0),
(102, 1, 'Penetration Step',               'Paso de penetración hacia adentro para entrar en single leg y double leg. Entrenado como movimiento de movilidad aislado.',                                                                    'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=74LN3ev3TAs', 'PUBLIC', NOW(), NOW(), 0),
(103, 1, 'Armbar Hip Extension Drill',     'Extensión de cadera explosiva desde posición de armbar en el suelo. Mejora el finishing del armbar y la movilidad lumbar.',                                                                    'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=hwgY6qlmdrk', 'PUBLIC', NOW(), NOW(), 0),
(104, 1, 'Guard Recovery Hip Circle',      'Círculos de cadera en el suelo para recuperar guardia cuando el rival intenta pasar. Trabaja amplitud y velocidad de cadera.',                                                                 'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=KX1G2RcZ6ro', 'PUBLIC', NOW(), NOW(), 0),
(105, 1, 'Bridge (Puente)',                'Puente de cadera explosivo desde el suelo. Base del escape de mount y ejercicio clave de calentamiento lumbar y glúteo.',                                                                       'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=tSvmWU-0Zo0', 'PUBLIC', NOW(), NOW(), 0),
(106, 1, 'Bridge and Roll Drill',          'Encadenado de puentes laterales para practicar el mecanismo completo de escape de mount. Combina explosividad y coordinación.',                                                                'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=Qq_yUhdYCUY', 'PUBLIC', NOW(), NOW(), 0),
(107, 1, 'Neck Mobility Circles',          'Círculos lentos y controlados de cuello para proteger la columna cervical en el tatami. Imprescindible antes y después de rodar.',                                                             'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=fsw9j3Hu-lg', 'PUBLIC', NOW(), NOW(), 0),
(108, 1, 'Shoulder Roll Forward',          'Rodada hacia adelante sobre el hombro para caídas seguras (ukemi) y transiciones fluidas en el suelo.',                                                                                        'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=Q3MT94wBXbI', 'PUBLIC', NOW(), NOW(), 0),
(109, 1, 'Shoulder Roll Backward',         'Rodada hacia atrás sobre el hombro, fundamental para ukemi en BJJ y escapar de presiones hacia atrás.',                                                                                        'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=iVOG3YyOrPQ', 'PUBLIC', NOW(), NOW(), 0),
(110, 1, 'Sprawl Drill',                   'Sprawl repetido para defensa de derribos. Trabaja la reacción de cadera y la extensión lumbar para neutralizar single y double legs.',                                                         'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=Adz0whT8wBc', 'PUBLIC', NOW(), NOW(), 0),
(111, 1, 'Wrestler''s Sit-Out Series',     'Serie de sit-outs encadenados de wrestling. Mejora la movilidad lateral y las transiciones rápidas cuando el rival tiene control de cintura.',                                                 'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=_kbBhyxV0RY', 'PUBLIC', NOW(), NOW(), 0),
(112, 1, 'Duck Walk',                      'Caminar en cuclillas profundas hacia adelante y atrás. Mejora la movilidad de cadera, rodilla y tobillo esencial para guard players.',                                                         'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=IVFB5KSxGBc', 'PUBLIC', NOW(), NOW(), 0),
(113, 1, 'Crab Walk',                      'Caminar como cangrejo con el cuerpo elevado del suelo. Trabaja movilidad de hombros, cadera y coordinación para posiciones de turtle.',                                                        'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=4JuKZA2jT6Y', 'PUBLIC', NOW(), NOW(), 0),
(114, 1, 'Inchworm',                       'Gusano: desde de pie, llevar las manos al suelo y avanzar hasta plancha, luego volver. Combina movilidad de isquiotibiales y tren superior.',                                                 'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=0HFXsIMKqUg', 'PUBLIC', NOW(), NOW(), 0),
(115, 1, 'Jiu-Jitsu Hip Mobility Flow',    'Flujo completo de movilidad de cadera encadenando shrimp + bridge + guard recovery roll. Calentamiento completo pre-sesión BJJ.',                                                              'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=raTdwv3d4GU', 'PUBLIC', NOW(), NOW(), 0),
(116, 1, 'Knee Circle Drill',              'Círculos de rodilla en postura de guardia para calentar la articulación antes de rodar. Previene lesiones en guard players.',                                                                  'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=92owncvIHlY', 'PUBLIC', NOW(), NOW(), 0),
(117, 1, 'Ankle Rotation Drill',           'Rotaciones de tobillo en todas las direcciones. Clave para guard players que trabajan leg locks y necesitan movilidad articular.',                                                             'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=QV-x1tK7U4w', 'PUBLIC', NOW(), NOW(), 0),
(118, 1, 'Wrist Mobility Drill',           'Movilidad y calentamiento de muñecas con círculos y extensiones. Imprescindible para wrestling, pummeling y clinch work.',                                                                     'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=7xY-JrvtnC0', 'PUBLIC', NOW(), NOW(), 0),
(120, 1, 'Hip Flexor Lunge Flow',          'Estocadas con flujo de cadera hacia adelante y atrás, añadiendo rotación. Abre el flexor de cadera para mejorar la guardia cerrada y abierta.',                                               'MOBILITY',    'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=tsGPYSQbZx4', 'PUBLIC', NOW(), NOW(), 0),
(121, 1, 'Butterfly Stretch',              'Estiramiento de aductores en posición de guardia mariposa: plantas de los pies juntas, rodillas hacia el suelo. Mejora la apertura de cadera.',                                               'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=VvMg0Bimxe8', 'PUBLIC', NOW(), NOW(), 0),
(122, 1, 'Hip Flexor Stretch',             'Apertura del flexor de cadera en posición de estocada baja. Mejora la guardia cerrada y la postura en el suelo.',                                                                             'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=NWVQxUFH9C4', 'PUBLIC', NOW(), NOW(), 0),
(123, 1, 'Seated Forward Fold',            'Flexión hacia adelante sentado con piernas extendidas. Estira isquiotibiales y zona lumbar, fundamental para guard play.',                                                                     'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=SLIaql7h6RQ', 'PUBLIC', NOW(), NOW(), 0),
(124, 1, 'Spinal Twist Stretch',           'Torsión espinal sentado cruzando una pierna. Mejora la movilidad de columna para barridas, guardias y transiciones rotacionales.',                                                             'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=mNdJti7ZwKI', 'PUBLIC', NOW(), NOW(), 0),
(125, 1, 'Pigeon Pose',                    'Apertura profunda de cadera en posición de paloma (yoga). Mejora significativamente la guardia y facilita los leg locks.',                                                                     'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=0zyhKn7b29I', 'PUBLIC', NOW(), NOW(), 0),
(126, 1, 'Frog Stretch',                   'Estiramiento de rana: rodillas separadas en el suelo, cadera hacia atrás. Para aductores profundos, essential en half guard y De La Riva.',                                                   'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=JDscdeuAzCU', 'PUBLIC', NOW(), NOW(), 0),
(127, 1, 'Standing Hip Circle',            'Círculos de cadera de pie con amplitud máxima. Calentamiento dinámico antes de rodar para activar toda la articulación de cadera.',                                                            'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=oU_oVMJL3-8', 'PUBLIC', NOW(), NOW(), 0),
(128, 1, 'Shoulder Cross-Body Stretch',    'Estiramiento de hombro cruzando el brazo ante el pecho. Previene lesiones de kimura y americana trabajando el manguito rotador.',                                                              'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=-1K0m5ywRcY', 'PUBLIC', NOW(), NOW(), 0),
(129, 1, 'Neck Lateral Stretch',           'Estiramiento lateral de cuello inclinando la cabeza hacia el hombro. Previene lesiones en guillotinas, darce y front headlock.',                                                               'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=54y0JAT46vE', 'PUBLIC', NOW(), NOW(), 0),
(130, 1, 'Thoracic Extension Stretch',     'Extensión torácica tumbado en el suelo o sobre un rodillo. Abre el pecho y mejora la postura en guardia, contrarrestando la cifosis del BJJ.',                                                 'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=ojCkd6_VdNk', 'PUBLIC', NOW(), NOW(), 0),
(132, 1, 'Pancake Stretch',                'Apertura de piernas con tronco inclinado hacia el suelo. Estiramiento avanzado para X-guard, leg entanglement y rubber guard.',                                                                'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=zLCHKQVl10g', 'PUBLIC', NOW(), NOW(), 0),
(133, 1, 'Straddle Stretch',               'Apertura de piernas sentado en el suelo, inclinando el tronco a cada lado. Esencial para De La Riva, rubber guard y guardias abiertas.',                                                      'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=TqK2dAvw-H4', 'PUBLIC', NOW(), NOW(), 0),
(134, 1, 'Cobra Pose',                     'Extensión lumbar suave boca abajo apoyándose en las manos. Contrarresta la posición encogida característica del BJJ y estira el abdomen.',                                                     'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=n6jrC6WeF84', 'PUBLIC', NOW(), NOW(), 0),
(135, 1, 'Child''s Pose',                  'Postura del niño: rodillas al suelo, brazos estirados al frente. Relaja la columna, hombros y caderas después del entrenamiento.',                                                             'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=kH12QrSGedM', 'PUBLIC', NOW(), NOW(), 0),
(136, 1, 'Lat Stretch Hanging',            'Estiramiento de dorsal colgado de una barra con una o dos manos. Mejora la capacidad de extensión para tomas largas y clinch work.',                                                           'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=quALD8pisKs', 'PUBLIC', NOW(), NOW(), 0),
(137, 1, 'Wrist Flexor Stretch',           'Estiramiento de flexores de muñeca extendiendo el brazo y tirando de los dedos hacia atrás. Previene lesiones en gripping y pummeling.',                                                      'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=R7dI2ZcbiMI', 'PUBLIC', NOW(), NOW(), 0),
(138, 1, 'Achilles and Calf Stretch',      'Estiramiento de gemelo y tendón de Aquiles contra la pared. Clave para guard players que mantienen posiciones de rodilla al suelo.',                                                           'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=mDxFZDA7Uq0', 'PUBLIC', NOW(), NOW(), 0),
(139, 1, 'Glute Stretch Figure-4',         'Estiramiento de glúteo en figura 4 tumbado o sentado. Mejora la salida de mount, la defensa de back control y el juego De La Riva.',                                                           'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=-g0nuyTHMrI', 'PUBLIC', NOW(), NOW(), 0),
(140, 1, 'Full Body BJJ Cool-Down Flow',   'Flujo completo de estiramientos post-entrenamiento BJJ: child''s pose + spinal twist + pigeon + butterfly + forward fold. 10 minutos de recuperación activa.',                                'FLEXIBILITY', 'NO_EQUIPMENT', 'https://www.youtube.com/watch?v=WxfPt3n44sc', 'PUBLIC', NOW(), NOW(), 0)
